INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Why is water described as a polar molecule, and how does this give rise to its properties?', 'Oxygen is more electronegative than hydrogen, so the O end is delta-negative and the H ends are delta-positive. Water molecules form hydrogen bonds, giving high specific heat capacity, high latent heat of vaporisation, cohesion/adhesion (transpiration stream), and excellent solvent properties for polar/ionic substances.', 1, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Compare alpha and beta glucose and explain how this affects polysaccharide structure.', 'Alpha-glucose has the OH on C1 below the ring, beta-glucose has it above. Alpha-glucose forms starch and glycogen (coiled, branched stores). Beta-glucose monomers must alternate orientation (every other one flipped 180°) to form straight, unbranched cellulose chains held by H-bonds into microfibrils.', 2, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'How does the structure of starch suit its function?', 'Amylose: helical, compact for storage. Amylopectin: branched (1,4 and 1,6 glycosidic bonds), giving many free ends for rapid hydrolysis by amylase. Insoluble (no osmotic effect) and large (cannot leave cells).', 3, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Describe the structure of a triglyceride and an ester bond.', 'One glycerol and three fatty acids joined by three ester bonds in condensation reactions (3 H2O released). Hydrocarbon tails are non-polar, making triglycerides hydrophobic and energy-dense.', 4, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'How do phospholipids form a bilayer in membranes?', 'The hydrophilic phosphate head faces aqueous environments while the hydrophobic fatty acid tails face inwards, away from water. This creates a partially permeable barrier. <svg viewBox="0 0 220 90" width="200" height="80" style="display:block;margin:6px auto"><g><circle cx="20" cy="20" r="6" fill="#0B1E3F"/><line x1="20" y1="26" x2="16" y2="45" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="26" x2="24" y2="45" stroke="#0B1E3F" stroke-width="1.5"/></g><g><circle cx="50" cy="20" r="6" fill="#0B1E3F"/><line x1="50" y1="26" x2="46" y2="45" stroke="#0B1E3F" stroke-width="1.5"/><line x1="50" y1="26" x2="54" y2="45" stroke="#0B1E3F" stroke-width="1.5"/></g><g><circle cx="80" cy="20" r="6" fill="#0B1E3F"/><line x1="80" y1="26" x2="76" y2="45" stroke="#0B1E3F" stroke-width="1.5"/><line x1="80" y1="26" x2="84" y2="45" stroke="#0B1E3F" stroke-width="1.5"/></g><g><circle cx="110" cy="20" r="6" fill="#0B1E3F"/><line x1="110" y1="26" x2="106" y2="45" stroke="#0B1E3F" stroke-width="1.5"/><line x1="110" y1="26" x2="114" y2="45" stroke="#0B1E3F" stroke-width="1.5"/></g><g><circle cx="20" cy="70" r="6" fill="#0B1E3F"/><line x1="20" y1="64" x2="16" y2="50" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="64" x2="24" y2="50" stroke="#0B1E3F" stroke-width="1.5"/></g><g><circle cx="50" cy="70" r="6" fill="#0B1E3F"/><line x1="50" y1="64" x2="46" y2="50" stroke="#0B1E3F" stroke-width="1.5"/><line x1="50" y1="64" x2="54" y2="50" stroke="#0B1E3F" stroke-width="1.5"/></g><g><circle cx="80" cy="70" r="6" fill="#0B1E3F"/><line x1="80" y1="64" x2="76" y2="50" stroke="#0B1E3F" stroke-width="1.5"/><line x1="80" y1="64" x2="84" y2="50" stroke="#0B1E3F" stroke-width="1.5"/></g><g><circle cx="110" cy="70" r="6" fill="#0B1E3F"/><line x1="110" y1="64" x2="106" y2="50" stroke="#0B1E3F" stroke-width="1.5"/><line x1="110" y1="64" x2="114" y2="50" stroke="#0B1E3F" stroke-width="1.5"/></g><text x="135" y="22" font-size="9" fill="#0B1E3F">hydrophilic head</text><text x="135" y="55" font-size="9" fill="#0B1E3F">hydrophobic tails</text><text x="135" y="74" font-size="9" fill="#0B1E3F">hydrophilic head</text></svg>', 5, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Describe the four levels of protein structure.', 'Primary: amino acid sequence (peptide bonds). Secondary: alpha helix or beta pleated sheet held by H-bonds between C=O and N-H. Tertiary: 3D fold, stabilised by H-bonds, ionic bonds, disulfide bridges, and hydrophobic interactions. Quaternary: 2+ polypeptide subunits (e.g. haemoglobin: 4 chains + 4 haem groups).', 6, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Explain the induced-fit model of enzyme action.', 'Substrate binds the active site, causing the enzyme to subtly change shape so the active site moulds tightly around the substrate. This places strain on bonds in the substrate, lowering activation energy. Enzyme returns to original shape after products leave.', 7, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'How does a competitive inhibitor differ from a non-competitive inhibitor?', 'Competitive: similar shape to substrate, binds active site, effect overcome by raising [substrate]. Non-competitive: binds an allosteric site, distorting the active site so substrate cannot bind; effect not overcome by [substrate].', 8, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Describe the structure of a DNA nucleotide and how a polynucleotide forms.', 'A deoxyribose sugar joined to a phosphate group and a nitrogenous base (A, T, C or G). Nucleotides join by phosphodiester bonds (condensation) between the 5'' phosphate of one and 3'' OH of the next, forming a sugar-phosphate backbone.', 9, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'State the base-pairing rules and the type of bonds between bases.', 'A pairs with T (2 H-bonds); C pairs with G (3 H-bonds). Strands run antiparallel (5''-3'' and 3''-5''). The two strands wind into a right-handed double helix.', 10, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Outline the role of ATP and how it is hydrolysed.', 'ATP -> ADP + Pi releases ~30.6 kJ mol^-1, catalysed by ATP hydrolase. The Pi can phosphorylate other molecules to make them more reactive. ATP is the universal energy currency of cells.', 11, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Give the reagents, observations and positive results for tests for sugars, starch, lipids, and protein.', 'Reducing sugar: Benedict''s, heat, blue -> brick red. Non-reducing sugar: hydrolyse with HCl, neutralise, then Benedict''s. Starch: iodine in KI, yellow -> blue-black. Lipids: emulsion test, ethanol then water, white emulsion. Protein: biuret, blue -> purple.', 12, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Why is water a good transport medium in plants and animals?', 'It is a polar solvent for ions/glucose/amino acids; cohesion (H-bonds) creates surface tension and continuous columns in xylem; high specific heat capacity buffers temperature; high latent heat of vaporisation makes evaporative cooling efficient.', 13, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'State the role of inorganic ions: H+, Fe2+, Na+, PO4^3-.', 'H+: pH determination, affects enzyme activity and transport. Fe2+: in haem of haemoglobin, binds O2. Na+: co-transport of glucose/amino acids in the ileum, generates membrane potentials. PO4^3-: in DNA/RNA backbones, ATP, phospholipids.', 14, 'alevel'),
  ('Biology', 'AQA', 'T1', 'Biological Molecules', 'Compare DNA and RNA.', 'DNA: deoxyribose, double-stranded, A-T-C-G, very long, stores genetic info. RNA: ribose, single-stranded, A-U-C-G, shorter, three types (mRNA, tRNA, rRNA) involved in protein synthesis.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T2', 'Cells', 'List the main organelles of a eukaryotic animal cell and one function of each.', 'Nucleus: stores DNA, transcription. Mitochondrion: aerobic respiration (ATP). Ribosome (80S): protein synthesis. RER: folds/transports proteins. SER: lipid/steroid synthesis. Golgi: modifies, packages, sorts proteins/glycoproteins. Lysosome: hydrolytic enzymes for digestion. Centrioles: spindle formation in mitosis.', 1, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'How does a prokaryote differ from a eukaryote?', 'Prokaryotes are smaller (~1-5 µm), have no nucleus (circular naked DNA in cytoplasm), 70S ribosomes, no membrane-bound organelles, a peptidoglycan cell wall, and may have plasmids, capsule, flagella and pili.', 2, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Compare TEM and SEM electron microscopes.', 'TEM: thin specimen, electrons pass through, very high resolution (~0.2 nm), 2D image of internal structure. SEM: surface scanned by electrons, lower resolution but 3D surface image. Both need vacuum and dead specimens, expensive, prone to artefacts.', 3, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Explain magnification vs resolution.', 'Magnification = how many times larger the image is than the object (image size / actual size). Resolution = minimum distance two points can be apart and still be distinguished. Light microscopes: ~200 nm; TEM: ~0.2 nm.', 4, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Outline cell fractionation and the order of organelle pellets.', 'Homogenise tissue in cold (slows enzymes), isotonic (prevents osmotic damage), buffered (stable pH) solution. Filter, then centrifuge in increasing speeds. Pellet order: nuclei -> chloroplasts (plants) -> mitochondria -> lysosomes -> ER -> ribosomes.', 5, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Describe the fluid-mosaic model of the plasma membrane.', 'A phospholipid bilayer (fluid) with proteins (mosaic) embedded. Includes channel/carrier proteins, glycoproteins/glycolipids (cell recognition), cholesterol (regulates fluidity). Partially permeable.', 6, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Compare facilitated diffusion and active transport.', 'Facilitated diffusion: passive, down a gradient, via channel/carrier proteins, no ATP. Active transport: uses ATP, against the gradient, via carrier proteins which change shape. Both saturate at high substrate concentrations.', 7, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Explain co-transport of glucose into ileum epithelial cells.', 'Na+/K+ pump on basal membrane uses ATP to pump Na+ out, lowering Na+ inside the cell. Na+ then re-enters with glucose via a co-transporter on the apical surface (down its gradient). Glucose then leaves into blood by facilitated diffusion.', 8, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Define water potential and describe how cells respond to hypotonic and hypertonic solutions.', 'Water potential = pressure exerted by water molecules; pure water = 0 kPa, solutions are negative. Animal cells: lyse in hypotonic, crenate in hypertonic. Plant cells: turgid in hypotonic (cell wall resists), plasmolysed in hypertonic.', 9, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Outline the stages of mitosis and the role in life cycles.', 'Prophase (chromosomes condense, nuclear envelope breaks down) -> Metaphase (chromosomes align on equator) -> Anaphase (sister chromatids pulled apart by spindle) -> Telophase (nuclear envelopes reform). Cytokinesis follows. Used for growth, repair, asexual reproduction; produces genetically identical diploid cells.', 10, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Sketch a typical mitotic index calculation.', 'Mitotic index = (cells in mitosis / total cells) x 100. Used to compare proliferation rates; high values may indicate cancerous tissue.', 11, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'How do cancer drugs target the cell cycle?', 'Some prevent DNA synthesis in S phase (e.g. methotrexate inhibits enzymes). Others prevent spindle formation in metaphase (e.g. vincristine). Side effects affect rapidly dividing healthy tissue (bone marrow, hair, gut).', 12, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Distinguish between the primary and secondary immune responses.', 'Primary: slow, low antibody peak, occurs on first exposure, person may show symptoms. Memory cells produced. Secondary: faster, larger antibody peak (memory B cells differentiate into plasma cells), often no symptoms — basis of immunity.', 13, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Outline the role of T helper, T killer and B cells.', 'T helper: bind antigen-presenting cells, release cytokines that stimulate B cells, T killer cells, and macrophages. T killer: kill infected cells via perforin. B cells: clonally selected by antigen, divide into plasma cells (secrete antibodies) and memory cells.', 14, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Describe the structure and action of an antibody.', 'A Y-shaped quaternary protein with two heavy and two light chains; constant and variable regions. Variable regions form two antigen-binding sites complementary to a specific antigen, causing agglutination and marking pathogens for phagocytosis.', 15, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'Distinguish active, passive, natural and artificial immunity.', 'Active: own antibodies made (memory). Passive: given antibodies (no memory). Natural: through normal life (e.g. infection / breast milk). Artificial: vaccines (active) / antibody injection (passive).', 16, 'alevel'),
  ('Biology', 'AQA', 'T2', 'Cells', 'How does HIV replicate and lead to AIDS?', 'HIV is a retrovirus that binds CD4 on T helper cells, RNA + reverse transcriptase enter, viral DNA integrates into the host genome. Eventually destroys T helpers, weakening immunity; AIDS = opportunistic infections take hold.', 17, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Why do larger organisms need specialised exchange surfaces?', 'As size increases, surface area : volume ratio decreases, so diffusion alone cannot meet metabolic demands. Specialised surfaces (lungs, gills, villi) provide a large SA, are thin, moist, well-supplied with blood, and ventilated to maintain gradients.', 1, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe gas exchange in fish gills (counter-current flow).', 'Water flows over gill lamellae in the opposite direction to blood. This maintains a concentration gradient along the entire length of the lamella, so ~80% of O2 is absorbed (vs ~50% with parallel flow).', 2, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe insect tracheal system gas exchange.', 'Air enters spiracles -> tracheae -> tracheoles -> tissues. Diffusion is supplemented by ventilation (abdominal pumping) and by water moving out of fluid-filled tracheole tips during activity, increasing surface area for gaseous diffusion.', 3, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe an alveolus and label features that aid exchange.', 'Many alveoli (~300 million) give a large SA (~70 m^2). Walls are squamous epithelium (one cell thick). Surrounded by capillaries (one cell thick). Lined by surfactant. Maintained gradients by breathing and circulation. <svg viewBox="0 0 200 120" width="180" height="110" style="display:block;margin:6px auto"><circle cx="80" cy="60" r="42" fill="#FFFFFF" stroke="#0B1E3F" stroke-width="2"/><circle cx="80" cy="60" r="36" fill="none" stroke="#0B1E3F" stroke-width="0.6"/><path d="M125,60 Q160,30 175,60 Q160,90 125,60" fill="none" stroke="#A33" stroke-width="1.5"/><circle cx="155" cy="60" r="3" fill="#A33"/><text x="60" y="62" font-size="10" fill="#0B1E3F">alveolus</text><text x="115" y="35" font-size="9" fill="#A33">capillary</text><line x1="80" y1="20" x2="115" y2="10" stroke="#0B1E3F" stroke-width="0.8"/><text x="115" y="12" font-size="9" fill="#0B1E3F">surfactant</text></svg>', 4, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'How does the structure of a plant leaf adapt for gas exchange?', 'Many stomata on the lower epidermis allow CO2 in / O2 out; spongy mesophyll has air spaces giving large internal SA; thin (short diffusion distance); guard cells regulate stomatal opening to balance gas exchange and water loss.', 5, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe the adaptations of a xerophyte.', 'Sunken/hairy stomata, thick waxy cuticle, rolled leaves, reduced leaf area (spines), CAM photosynthesis (stomata open at night). All reduce transpiration in dry/hot environments.', 6, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'How are starch, proteins and lipids digested and absorbed?', 'Starch: amylase -> maltose -> maltase -> alpha-glucose. Proteins: endopeptidases (trypsin) cut middle, exopeptidases (carboxy/aminopeptidase) cut ends, dipeptidases finish. Lipids: emulsified by bile salts, lipase -> fatty acids + monoglycerides, absorbed via micelles into ileum cells, reformed and exported as chylomicrons via lacteals.', 7, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe the structure of a villus.', 'Finger-like projections on the ileum wall (large SA). One-cell-thick epithelium with microvilli increasing SA further. Rich blood supply (capillary network) maintains gradients. Lacteal absorbs lipids. Membrane has carriers for active transport / co-transport.', 8, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe a single complete cardiac cycle.', 'Atrial systole: atria contract, AV valves open, ventricles fill. Ventricular systole: ventricles contract, AV valves close (1st heart sound), SL valves open, blood ejected. Diastole: ventricles relax, SL valves close (2nd heart sound), atria fill from veins. Cycle ~0.8 s.', 9, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Sketch and explain the oxyhaemoglobin dissociation curve.', 'A sigmoidal curve: low affinity at low pO2, then cooperative binding causes a steep rise as further O2 binds more easily. The Bohr shift moves the curve right when CO2/H+ rises (active tissues), unloading more O2. <svg viewBox="0 0 200 130" width="180" height="120" style="display:block;margin:6px auto"><line x1="25" y1="110" x2="190" y2="110" stroke="#0B1E3F" stroke-width="1.5"/><line x1="25" y1="110" x2="25" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M25,108 Q60,105 80,80 Q105,40 150,25 L185,22" fill="none" stroke="#0B1E3F" stroke-width="2"/><path d="M25,109 Q70,107 95,90 Q120,55 160,35 L185,30" fill="none" stroke="#A33" stroke-width="1.5" stroke-dasharray="3,2"/><text x="2" y="60" font-size="9" fill="#0B1E3F">% sat</text><text x="80" y="125" font-size="9" fill="#0B1E3F">pO2 / kPa</text><text x="120" y="60" font-size="8" fill="#A33">+ CO2 (Bohr)</text></svg>', 10, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Compare arteries, veins and capillaries.', 'Arteries: thick muscular wall, narrow lumen, elastic, high pressure, no valves. Veins: thin wall, wide lumen, low pressure, valves prevent backflow. Capillaries: one cell thick, narrow (~5-10 µm), large total SA for exchange.', 11, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Explain tissue fluid formation and lymph.', 'At the arterial end of a capillary, hydrostatic pressure > oncotic (solute) pressure, forcing fluid out. At the venous end, hydrostatic pressure has dropped while oncotic pressure (proteins remain) draws fluid back in. Excess fluid (lymph) is returned via lymphatic vessels.', 12, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe the cohesion-tension theory of water transport in xylem.', 'Water evaporates from spongy mesophyll cells -> stomata (transpiration). This creates a tension/negative pressure in xylem, drawing water up. Water molecules cohere by H-bonds (continuous column) and adhere to xylem walls (capillary action).', 13, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Outline the mass-flow hypothesis for translocation in phloem.', 'At the source (e.g. leaf), sucrose is loaded into sieve tubes by active transport (H+/sucrose co-transport), lowering water potential. Water enters from xylem by osmosis, raising hydrostatic pressure. Sucrose flows down a pressure gradient to the sink (e.g. root) where it is unloaded and used or stored.', 14, 'alevel'),
  ('Biology', 'AQA', 'T3', 'Organisms Exchange Substances', 'Describe how a potometer is used.', 'Cut shoot underwater, attach to capillary tube full of water, ensure airtight. Record distance the air bubble moves over time -> rate of water uptake (proxy for transpiration). Vary temperature/humidity/wind/light to investigate effects.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Distinguish gene, allele, locus, genome and proteome.', 'Gene: a section of DNA coding for a polypeptide / functional RNA. Allele: a variant of a gene. Locus: the position of a gene on a chromosome. Genome: all the genetic material in an organism. Proteome: all the proteins it can make.', 1, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Describe the genetic code.', 'Triplet (3 bases code 1 amino acid), non-overlapping, degenerate (multiple codons per amino acid), universal (same in nearly all organisms), and contains start (AUG) and stop codons.', 2, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Compare prokaryotic and eukaryotic genes.', 'Prokaryotic genes are continuous (no introns) and DNA is circular and naked. Eukaryotic genes have introns (non-coding) and exons (coding); DNA is linear and bound to histones forming chromatin.', 3, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Explain semi-conservative DNA replication.', 'DNA helicase unwinds the helix, breaking H-bonds between bases. Free DNA nucleotides align with their complement on each parental strand. DNA polymerase forms phosphodiester bonds. Each new molecule has one parental and one new strand.', 4, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Describe transcription.', 'In the nucleus, RNA polymerase binds the promoter; the gene is unwound; complementary RNA nucleotides (U for A) align on the template strand and are joined to form pre-mRNA. After splicing (introns removed), mature mRNA leaves via a nuclear pore.', 5, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Describe translation.', 'mRNA binds a ribosome; the start codon AUG attracts a tRNA carrying methionine. The next tRNA with the complementary anticodon binds; a peptide bond forms between the amino acids; the ribosome moves one codon along. Continues until a stop codon is reached.', 6, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Describe four types of gene mutation and a possible effect of each.', 'Substitution: usually limited (degenerate code) or missense/nonsense. Insertion/Deletion: cause frameshift -> all subsequent amino acids changed. Duplication: extends frame, often disruptive. Inversion: amino acid sequence reversed in section. Mutations may be silent, beneficial, or harmful.', 7, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Outline meiosis and how it produces genetic variation.', 'Two divisions produce 4 haploid daughter cells. Sources of variation: independent assortment of homologous chromosomes (metaphase I) and sister chromatids (metaphase II), plus crossing-over between non-sister chromatids in prophase I. Random fertilisation adds further variation.', 8, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Define genetic diversity and three sources of variation.', 'Genetic diversity = number of different alleles in a population. Sources: mutation, meiosis (independent assortment, crossing over), random fertilisation. Higher diversity = more raw material for natural selection.', 9, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Describe directional, stabilising and disruptive selection.', 'Directional: extreme phenotype favoured (e.g. antibiotic resistance), shifts mean. Stabilising: intermediate phenotype favoured (e.g. human birth weight), reduces variance. Disruptive: both extremes favoured, may lead to speciation.', 10, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Define species using two criteria.', 'Phylogenetic: sharing an evolutionary lineage. Biological: members can interbreed to produce fertile offspring. Mules (horse x donkey) are infertile -> different species.', 11, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Describe the binomial naming system and the eight taxonomic ranks.', 'Genus + species (italicised), e.g. Homo sapiens. Ranks: domain, kingdom, phylum, class, order, family, genus, species. Three domains: Bacteria, Archaea, Eukarya.', 12, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Why do molecular methods (DNA sequencing, immunology) improve classification?', 'Direct comparison of DNA / protein sequences gives quantitative data; closer relatives have fewer differences. They reveal evolutionary relationships hidden by convergent morphology and confirm phylogenies independently of physical traits.', 13, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'Define species richness and an index of diversity.', 'Species richness = number of species in a community. Simpson''s index D = 1 - sum(n/N)^2 (n = number of organisms of a species, N = total). Higher D = more diverse and more stable community.', 14, 'alevel'),
  ('Biology', 'AQA', 'T4', 'Genetic Information, Variation & Relationships', 'How does intensive farming reduce biodiversity, and how can this be mitigated?', 'Monoculture, hedgerow removal, pesticides, fertilisers and drainage reduce habitats and species. Mitigations: maintain hedgerows, intercropping, organic methods, conservation headlands, agri-environment schemes.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Write the overall equation for photosynthesis and state its two stages.', '6CO2 + 6H2O -> C6H12O6 + 6O2 (light required). Stage 1: light-dependent reactions in thylakoids. Stage 2: light-independent (Calvin cycle) in stroma.', 1, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Outline the light-dependent reactions.', 'Photolysis of water at PSII: 2H2O -> 4H+ + 4e- + O2. Excited electrons travel down ETC (PSII -> PSI), pumping H+ into the thylakoid lumen. Chemiosmosis: H+ flow back through ATP synthase makes ATP. NADP+ + H+ + 2e- -> NADPH.', 2, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Describe the Calvin cycle.', 'CO2 + RuBP (5C) -> 2 GP (3C) catalysed by RuBisCO. GP reduced to TP using ATP and NADPH. Some TP forms glucose; most regenerates RuBP using ATP. Six turns produce one glucose.', 3, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'How do light, CO2 and temperature limit photosynthesis?', 'Light: rate increases with intensity until light-saturation. CO2: rate increases until other factor limiting (~0.4% CO2). Temperature: rate rises with T to ~25-30 °C, then enzymes denature. The lowest factor at any time is the limiting factor.', 4, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'List the four stages of aerobic respiration and their locations.', 'Glycolysis (cytoplasm), link reaction (matrix), Krebs cycle (matrix), oxidative phosphorylation (inner mitochondrial membrane).', 5, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Outline glycolysis.', 'Glucose phosphorylated using 2 ATP -> hexose bisphosphate -> 2 triose phosphate. Each TP oxidised to pyruvate, generating 4 ATP and 2 NADH. Net: 2 ATP and 2 NADH per glucose. Anaerobic and occurs in cytoplasm.', 6, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Describe the link reaction and Krebs cycle (per glucose).', 'Link: 2 pyruvate -> 2 acetyl-CoA, releasing 2 CO2 and 2 NADH. Krebs (x2): each acetyl-CoA + 4C -> 6C; decarboxylation/dehydrogenation give 2 CO2, 3 NADH, 1 FADH2 and 1 ATP. Per glucose: 4 CO2, 6 NADH, 2 FADH2, 2 ATP.', 7, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Explain oxidative phosphorylation by chemiosmosis.', 'NADH/FADH2 deliver electrons to the ETC on the inner mitochondrial membrane. As electrons pass, H+ is pumped to the intermembrane space. H+ flows back through ATP synthase to the matrix, driving ATP synthesis. Final electron acceptor: O2 -> H2O.', 8, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Compare lactate and ethanol fermentation.', 'In animals: pyruvate + NADH -> lactate + NAD+ (reversible; lactate -> liver). In yeast/plants: pyruvate -> ethanal + CO2 -> ethanol (irreversible, NAD+ regenerated). Both regenerate NAD+ so glycolysis can continue without O2.', 9, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Explain why fats yield more ATP per gram than carbohydrates.', 'Fats have many more C-H bonds per molecule than carbohydrates, so beta-oxidation produces more acetyl-CoA -> more NADH and FADH2 entering the ETC -> ~2x ATP yield per gram (~37 vs ~17 kJ/g).', 10, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Define GPP, NPP and write the relationship.', 'GPP = total chemical energy in plant biomass per unit area per unit time. NPP = GPP - respiratory loss. NPP available to next trophic level. Units: kJ m^-2 yr^-1.', 11, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Why is energy transfer between trophic levels inefficient?', 'Not all the previous level is eaten or digested; energy lost as heat from respiration, in faeces, urine and undigested parts. Typical transfer ~10% (plants -> herbivores) up to ~20% (carnivores).', 12, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Describe the nitrogen cycle and the four key types of bacteria.', 'Saprobionts decompose proteins to ammonium (ammonification). Nitrifying bacteria (Nitrosomonas, Nitrobacter) oxidise NH4+ -> NO2- -> NO3-. Nitrogen-fixing bacteria (Rhizobium, Azotobacter) fix N2 -> NH3. Denitrifying bacteria reduce NO3- -> N2 in anaerobic soils.', 13, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'Describe the phosphorus cycle.', 'Rocks weather, releasing PO4^3- ions into soil/water. Plants take up PO4^3- by active transport; passes along food chains. Decomposers and animal waste return PO4^3- to soil. Guano and fertilisers add PO4^3- to crops; runoff causes eutrophication.', 14, 'alevel'),
  ('Biology', 'AQA', 'T5', 'Energy Transfers', 'How does eutrophication arise?', 'Nitrate/phosphate runoff -> rapid algal growth (algal bloom) -> blocks light to plants below -> plants die -> saprobionts decompose them, depleting O2 -> aerobic organisms (e.g. fish) die.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Define a tropism and contrast positive and negative phototropism.', 'A tropism is a directional growth response. Positive phototropism: shoots grow towards light (auxin (IAA) accumulates on shaded side, elongates cells). Negative phototropism: roots grow away from light, as IAA inhibits root cell elongation.', 1, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Describe a simple reflex arc.', 'Stimulus -> receptor -> sensory neurone -> relay neurone (in spinal cord) -> motor neurone -> effector (muscle/gland) -> response. Bypasses the brain (faster, protective).', 2, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Explain how a Pacinian corpuscle generates a generator potential.', 'Pressure deforms the lamellae and stretches the membrane. Stretch-mediated Na+ channels open; Na+ enters, depolarising the membrane. If above threshold, an action potential is triggered in the sensory neurone.', 3, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Compare rod and cone cells.', 'Rods: high sensitivity (many rods per bipolar cell -> retinal convergence), monochromatic, used in low light, contain rhodopsin. Cones: low sensitivity (1:1 with bipolar), high acuity, three types (red/green/blue) for colour vision, contain iodopsin, concentrated in fovea.', 4, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Describe how the heart rate is controlled by the SAN, AVN and Purkyne fibres.', 'SAN (right atrium) sets pace; wave of depolarisation spreads across atria -> contraction. Annulus fibrosus delays signal; AVN passes the impulse to the Bundle of His. Purkyne fibres carry it down the septum to the apex, ventricles contract from the bottom up.', 5, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'How is heart rate adjusted by the medulla and baroreceptors?', 'Pressoreceptors in aortic arch/carotid sinus signal to medulla. High BP -> parasympathetic (vagus) -> decrease rate. Low BP / high CO2 -> sympathetic (accelerator nerve) -> increase rate. Chemoreceptors detect blood CO2/pH.', 6, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Sketch and label an action potential.', 'Resting potential (-70 mV) -> stimulus depolarises to threshold (-55 mV). Voltage-gated Na+ channels open: rapid rise to +40 mV. Na+ channels close, K+ channels open: repolarisation. Hyperpolarisation as K+ overshoots, then Na+/K+ pump restores resting potential. <svg viewBox="0 0 200 130" width="180" height="120" style="display:block;margin:6px auto"><line x1="20" y1="80" x2="190" y2="80" stroke="#0B1E3F" stroke-width="0.5" stroke-dasharray="3,2"/><line x1="20" y1="115" x2="190" y2="115" stroke="#0B1E3F" stroke-width="1.5"/><line x1="20" y1="115" x2="20" y2="15" stroke="#0B1E3F" stroke-width="1.5"/><path d="M20,90 L60,90 L80,20 L100,90 L120,105 L160,90 L190,90" fill="none" stroke="#0B1E3F" stroke-width="2"/><text x="2" y="22" font-size="9" fill="#0B1E3F">+40</text><text x="2" y="93" font-size="9" fill="#0B1E3F">-70</text><text x="80" y="128" font-size="9" fill="#0B1E3F">time / ms</text><text x="60" y="55" font-size="8" fill="#0B1E3F">depol</text><text x="100" y="55" font-size="8" fill="#0B1E3F">repol</text></svg>', 7, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Explain the all-or-nothing principle and frequency coding.', 'Once threshold is reached, an action potential of a fixed amplitude is fired; sub-threshold stimuli give nothing. Stimulus strength is encoded by frequency of action potentials and the number of neurones firing.', 8, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'How does a myelin sheath increase conduction speed?', 'Myelin (Schwann cells) is electrically insulating. Action potentials only occur at the unmyelinated nodes of Ranvier, so the impulse "jumps" from node to node (saltatory conduction), much faster than continuous conduction.', 9, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Describe synaptic transmission at a cholinergic synapse.', 'AP arrives at presynaptic knob -> Ca2+ channels open -> Ca2+ enters -> vesicles fuse with membrane and release ACh. ACh diffuses across the cleft, binds receptors on postsynaptic membrane, opening Na+ channels. Acetylcholinesterase breaks ACh into choline + acetate, taken back into the presynaptic neurone.', 10, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Compare temporal and spatial summation.', 'Temporal: one presynaptic neurone fires repeatedly in quick succession; combined NT release exceeds threshold. Spatial: several presynaptic neurones release NT at the same postsynaptic neurone simultaneously to reach threshold.', 11, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Describe sliding filament theory.', 'Ca2+ released from sarcoplasmic reticulum binds troponin, moving tropomyosin so myosin heads bind actin. ATP hydrolysis powers the power stroke, sliding actin past myosin, shortening the sarcomere. New ATP binds, myosin detaches, cycle repeats.', 12, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Compare slow- and fast-twitch muscle fibres.', 'Slow-twitch: aerobic, many mitochondria, lots of myoglobin, fatigue-resistant (e.g. postural muscles). Fast-twitch: anaerobic glycolysis, few mitochondria, large stores of glycogen and phosphocreatine, fatigue quickly (e.g. sprinting).', 13, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Define homeostasis and explain why it is essential.', 'Maintenance of a constant internal environment within tolerance limits. Stable enzyme activity (T, pH), normal cell water potential, and constant blood glucose ensure cells function efficiently despite external changes.', 14, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Explain the second-messenger model of glucagon action.', 'Glucagon binds a receptor on liver cells -> activates G-protein -> adenylyl cyclase -> ATP -> cAMP (second messenger) -> protein kinase A -> phosphorylates enzymes -> glycogenolysis, releasing glucose into blood.', 15, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Describe how insulin reduces blood glucose.', 'Binds tyrosine kinase receptors on liver/muscle/fat cells -> more GLUT4 transporters inserted, increased glucose uptake. Activates glycogen synthase -> glycogenesis. Inhibits gluconeogenesis. Promotes lipogenesis.', 16, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Compare type 1 and type 2 diabetes.', 'Type 1: autoimmune destruction of beta-cells; insulin not produced; treated with insulin injections. Type 2: cells become insulin-resistant; managed with diet, exercise and metformin. Risk factors: obesity, age, genetics.', 17, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Outline ultrafiltration and selective reabsorption in the nephron.', 'Glomerulus: high BP forces small molecules (water, glucose, urea, ions) through fenestrated capillary, basement membrane and podocytes into Bowman''s capsule. Proximal convoluted tubule: glucose and amino acids are completely reabsorbed by Na+ co-transport; water follows osmotically.', 18, 'alevel'),
  ('Biology', 'AQA', 'T6', 'Organisms Respond to Changes', 'Explain the role of ADH in osmoregulation.', 'When blood is too concentrated, osmoreceptors in the hypothalamus stimulate the posterior pituitary to release ADH. ADH increases collecting duct permeability to water (more aquaporins inserted), so more water is reabsorbed; small volume of concentrated urine is produced.', 19, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Define genotype, phenotype, homozygous and heterozygous.', 'Genotype: alleles an organism has. Phenotype: observable characteristics. Homozygous: two identical alleles (e.g. AA, aa). Heterozygous: two different alleles (Aa).', 1, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Explain a monohybrid cross with a 3:1 ratio.', 'Aa x Aa offspring: AA : Aa : Aa : aa = 3 dominant : 1 recessive phenotype. Each parent gives one allele at random.', 2, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Describe a dihybrid cross and the 9:3:3:1 ratio.', 'Two unlinked genes; AaBb x AaBb gives 9 A_B_ : 3 A_bb : 3 aaB_ : 1 aabb. Confirms independent assortment of unlinked genes (Mendel''s second law).', 3, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Define autosomal linkage and how it affects ratios.', 'Two genes on the same autosome are inherited together unless crossing over occurs. Offspring ratios deviate from expected 9:3:3:1, with parental phenotypes in excess and recombinants reduced.', 4, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Explain sex linkage using haemophilia.', 'Allele on X chromosome (X^h). Females need two X^h to be affected (X^H X^h are carriers); males with one X^h Y are affected. Hence haemophilia is more common in males.', 5, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Define epistasis and give an example.', 'One gene masks/modifies the expression of another. E.g. coat colour in Labradors: BB or Bb gives black, bb gives brown — but ee at a separate locus blocks pigment, giving yellow regardless of B allele.', 6, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Use chi-squared (chi^2) to test goodness of fit.', 'chi^2 = sum((O - E)^2 / E). Compare with critical value at degrees of freedom = (categories - 1), p = 0.05. If chi^2 > critical, reject null hypothesis (deviation significant).', 7, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'State the Hardy-Weinberg principle and equations.', 'Allele frequencies stay constant if: large population, no mutation, no migration, no selection, random mating. p + q = 1; p^2 + 2pq + q^2 = 1.', 8, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Distinguish stabilising, directional and disruptive selection with curve sketches.', 'Stabilising: peak narrows around the same mean. Directional: peak shifts to one extreme. Disruptive: bimodal — extremes favoured.', 9, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Define allopatric vs sympatric speciation.', 'Allopatric: a geographical barrier separates populations; different selection pressures and mutations cause divergence; eventually reproductive isolation. Sympatric: reproductive isolation arises in the same area (e.g. polyploidy in plants, behavioural isolation).', 10, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Compare carrying capacity and limiting factors.', 'Carrying capacity = maximum population an environment can sustain. Limiting factors are density-dependent (food, predators, disease) or density-independent (drought, fire, climate).', 11, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Sketch predator-prey cycles.', 'Prey rises -> predators have more food, increase -> prey decreases -> predators starve, decrease -> prey recovers. Out-of-phase oscillations; predator peaks lag prey peaks.', 12, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Describe primary succession from bare rock to climax community.', 'Pioneer species (e.g. lichens) colonise rock, releasing organic matter as they die -> mosses, then small plants, grasses, shrubs, woodland. Each stage modifies the abiotic environment (soil, light) until a climax community is reached.', 13, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Outline how to estimate population size with mark-release-recapture.', 'Catch a sample, mark, release, allow to mix, recapture. Population N = (n1 x n2) / m, where n1 = first sample size, n2 = second sample size, m = marked recaptures. Assumes no births/deaths/migration and that marking does not affect survival.', 14, 'alevel'),
  ('Biology', 'AQA', 'T7', 'Genetics, Populations, Evolution & Ecosystems', 'Why is conservation often based on managed succession?', 'Allowing a single climax community reduces biodiversity. By cutting/grazing, succession is held at an earlier seral stage that supports a wider range of species (e.g. heathland, chalk grassland).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'How is gene expression regulated by transcription factors?', 'Transcription factors bind specific promoter sequences and either recruit or block RNA polymerase. They are produced in response to internal or external signals (e.g. hormones), allowing only relevant genes to be transcribed in a given cell type.', 1, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Explain how oestrogen activates gene transcription.', 'Lipid-soluble oestrogen diffuses through the membrane and binds an intracellular receptor (TF). The complex enters the nucleus, binds DNA at hormone response elements, and stimulates transcription of target genes.', 2, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Distinguish DNA methylation and histone acetylation.', 'DNA methylation (adding -CH3 to cytosine of CpG islands) typically silences a gene. Histone acetylation loosens DNA-histone binding, making the gene easier to transcribe. Both are reversible epigenetic modifications.', 3, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'How do siRNA / miRNA regulate gene expression?', 'Short RNA molecules base-pair with complementary mRNA. siRNA usually leads to mRNA cleavage by the RISC complex; miRNA usually inhibits translation. Both reduce protein synthesis from a specific gene.', 4, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Define totipotent, pluripotent, multipotent and unipotent stem cells.', 'Totipotent: form any cell type incl. extra-embryonic (zygote, early morula). Pluripotent: any cell type of the body (embryonic SC). Multipotent: limited range (haematopoietic SC). Unipotent: one cell type (cardiac muscle progenitors).', 5, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Outline how iPS cells are made and an advantage over ES cells.', 'Adult somatic cells are reprogrammed by transcription factors (e.g. Oct4, Sox2, Klf4, c-Myc) to a pluripotent state. Avoid ethical issues of embryos and rejection (patient-specific).', 6, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Describe how oncogenes and tumour suppressor genes lead to cancer.', 'Proto-oncogenes regulate cell division; mutation makes them constitutively active oncogenes -> uncontrolled division. Tumour suppressor genes (e.g. p53) normally pause the cycle; loss-of-function mutations remove the brake. Both contribute to malignant tumours.', 7, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Explain how methylation of BRCA1 can lead to cancer.', 'Hypermethylation of the BRCA1 promoter silences this tumour suppressor gene. DNA repair is impaired, so further mutations accumulate -> increased risk of breast/ovarian cancer.', 8, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Describe how DNA fragments can be made for cloning.', 'Three methods: reverse transcriptase from mRNA -> cDNA; restriction endonucleases cut at specific palindromic sequences leaving sticky ends; gene synthesis using known sequences (oligonucleotides).', 9, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Outline the polymerase chain reaction (PCR).', 'Cycles of: denature (95 °C) to separate strands -> anneal (~55 °C) primers to target sequence -> extend (72 °C) by Taq DNA polymerase. Each cycle doubles the DNA -> 2^n copies after n cycles.', 10, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Outline gel electrophoresis of DNA.', 'DNA fragments are loaded into agarose gel wells; an electric field drives the negatively charged DNA towards the anode. Smaller fragments move further. Stains (e.g. ethidium bromide) reveal bands under UV. Used in DNA profiling and PCR analysis.', 11, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Describe how a gene is inserted into a bacterial plasmid.', 'Same restriction enzyme cuts gene and plasmid, creating complementary sticky ends. DNA ligase joins them by phosphodiester bonds. Plasmid (vector) is taken up by host bacterium (transformation), often with help of CaCl2 and heat shock.', 12, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'How are successfully transformed bacteria identified using marker genes?', 'Replica plating onto antibiotic-containing media; only bacteria carrying the plasmid survive. Insertional inactivation (e.g. lacZ disrupted -> white colonies) or fluorescent markers (GFP) confirm the gene of interest has been successfully inserted.', 13, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Define DNA probes and a Southern blot.', 'A DNA probe is a single-stranded labelled DNA sequence complementary to a target. In Southern blotting, fragments are separated by gel electrophoresis, transferred to a membrane, and the probe binds the target -> visualised by radioactivity or fluorescence.', 14, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Outline DNA profiling and one application.', 'PCR amplifies regions containing variable number tandem repeats (VNTRs). Fragments are separated by gel electrophoresis, giving a banding pattern unique to the individual (except identical twins). Used in paternity, forensics, and identifying genetic relationships.', 15, 'alevel'),
  ('Biology', 'AQA', 'T8', 'Control of Gene Expression', 'Compare somatic and germline gene therapy.', 'Somatic: target cells of an individual (e.g. lung cells in CF). Effects not heritable. Germline: alters egg/sperm/embryo so changes are passed on; banned in humans for ethical reasons.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Define independent, dependent and control variables, and give an example.', 'IV: variable manipulated by the experimenter (e.g. temperature). DV: variable measured (e.g. rate of O2 production). Controls: variables held constant (pH, [enzyme], [substrate]). Without controls, changes in DV cannot be attributed to the IV.', 1, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Distinguish accuracy, precision, reliability and validity.', 'Accuracy: closeness to true value. Precision: small spread between repeats. Reliability: same results on repetition. Validity: investigation answers the original question and only the IV affected the DV.', 2, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Describe RP1: investigating the effect of pH on amylase activity.', 'Set up buffers at different pH; mix equal volumes of amylase and starch in each. At intervals, sample with iodine on a tile; record time for the iodine to stop turning blue-black (starch fully digested). Rate = 1/time. Optimum ~ pH 7.', 3, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Outline RP2: preparing and observing a root tip squash for mitosis.', 'Cut tip (~5 mm) from a growing root (e.g. garlic), warm in 1 mol/dm^3 HCl to break cell walls, rinse, place on slide and stain with toluidine blue / acetic orcein. Squash with cover slip to spread cells. Calculate mitotic index = (cells in mitosis / total cells) x 100.', 4, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Describe RP3: dilution series and a calibration curve using a colorimeter.', 'Make a serial dilution of a standard (e.g. glucose) and react with Benedict''s. Filter precipitate; measure absorbance with red filter. Plot absorbance vs concentration to give a calibration curve. Use to find unknown [glucose] from its absorbance.', 5, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'How is RP4 (beetroot membrane permeability) carried out?', 'Cut equal-sized beetroot cylinders, rinse off cell-content pigment. Place in water at varied temperatures (or [ethanol]) for fixed time. Measure absorbance of red leaked betacyanin in colorimeter (~470 nm). Higher absorbance -> more leaked -> more disrupted membrane.', 6, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Describe RP6: aseptic technique with antimicrobial substances.', 'Sterilise inoculating loop in flame, work near a Bunsen, lift agar lid at angle. Spread bacterial culture, place paper discs soaked in antimicrobials. Incubate <25 °C (UK schools). Measure clear zone of inhibition (mm); larger zone = greater antimicrobial activity.', 7, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Outline RP7: chromatography of leaf pigments.', 'Grind leaves with sand and propanone to extract pigments. Spot solvent front on chromatography paper, spot pigment carefully, place in solvent. Calculate Rf = distance moved by spot / distance moved by solvent. Compare Rf to known pigments (chlorophyll a, b, carotene, xanthophyll).', 8, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Describe RP8: respirometer method.', 'Use a respirometer with KOH (absorbs CO2) and a manometer. Measure how far the coloured fluid moves over time -> volume of O2 used by germinating seeds / maggots. Calculate rate; control with glass beads (no respiration). <svg viewBox="0 0 220 90" width="200" height="80" style="display:block;margin:6px auto"><rect x="20" y="25" width="60" height="40" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><text x="36" y="48" font-size="9" fill="#0B1E3F">seeds</text><text x="32" y="60" font-size="8" fill="#0B1E3F">+ KOH</text><line x1="80" y1="45" x2="200" y2="45" stroke="#0B1E3F" stroke-width="1.5"/><circle cx="120" cy="45" r="3" fill="#A33"/><text x="100" y="35" font-size="9" fill="#0B1E3F">manometer</text><text x="115" y="60" font-size="9" fill="#A33">droplet</text></svg>', 9, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Describe RP10: estimating distribution and abundance with quadrats and transects.', 'Random sampling: generate random coordinates with a tape and place quadrats. Systematic: place quadrats at fixed intervals along a line/belt transect (used when an environmental gradient exists). Calculate frequency, percentage cover, and density to compare habitats.', 10, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'How is a serial dilution prepared accurately?', 'Pipette equal volumes (e.g. 1 cm^3) of stock into test tubes. Add equal volumes of solvent (e.g. 9 cm^3 distilled water) to each tube and mix between transfers. This creates a 10-fold (1 in 10) dilution series. Use a fresh pipette tip each time to prevent cross-contamination.', 11, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'Why are repeats and means used, and how is anomalous data treated?', 'Repeats reduce the impact of random errors and reveal precision (range). Means smooth small variations. Identify anomalies (clearly outside the range) by inspection; ignore them when calculating the mean but record them honestly.', 12, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'How is a t-test used in biology?', 'Compares the means of two normally-distributed samples. Calculate t, look up the critical value at (n1 + n2 - 2) degrees of freedom, p = 0.05. If t > critical, reject H0 -> the difference between means is statistically significant.', 13, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'How does a haemocytometer work?', 'A haemocytometer is a calibrated counting chamber. Fill with diluted cell suspension under a coverslip; count cells in a known volume of grid squares. Cells / cm^3 = (mean count per square) / (square volume) x dilution factor.', 14, 'alevel'),
  ('Biology', 'AQA', 'RP', 'Required Practicals & Practical Skills', 'List the safety / ethics considerations for handling microorganisms.', 'Use aseptic technique near a Bunsen, sterilise tools, work on a disinfected bench, avoid lifting agar lids fully, incubate sealed plates at <25 °C, autoclave waste. Ethics: only work with non-pathogenic organisms approved for school use.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Describe how a condensation reaction forms a glycosidic bond.', 'OH groups on adjacent monosaccharides react; one H and one OH are lost as water (H2O). The resulting glycosidic bond is named by the carbon atoms it links, e.g. alpha-1,4 in maltose. Hydrolysis reverses it using water.', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Compare the structure and function of starch and glycogen.', 'Both are alpha-glucose polymers; both are coiled, branched (1,4 and 1,6), insoluble (no osmotic effect), and compact storage molecules. Glycogen is more highly branched than starch -> faster hydrolysis to meet animal energy demands.', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'How does the structure of cellulose adapt it for plant cell walls?', 'Beta-glucose polymers; alternating monomer orientation gives unbranched chains. Many H-bonds between chains form microfibrils, which assemble into macrofibrils. High tensile strength resists cell turgor pressure.', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Distinguish saturated, monounsaturated and polyunsaturated fatty acids.', 'Saturated: no C=C double bonds, straight chain, solid at room T (animal fats). Monounsaturated: one C=C; polyunsaturated: 2+ C=C, kinked chains pack less well, so liquid (oils). Cis/trans isomerism affects packing and health implications.', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Compare HDL and LDL.', 'LDL: low-density lipoprotein, transports cholesterol from liver to body tissues; high LDL deposits cholesterol in artery walls (atheromas). HDL: high-density lipoprotein, removes excess cholesterol from tissues to liver. High HDL : LDL ratio reduces CVD risk.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Describe the formation of an ester bond between glycerol and a fatty acid.', 'COOH of the fatty acid reacts with OH of glycerol. A condensation reaction releases water, forming an ester bond -O-CO-. Three condensations form a triglyceride (3 H2O). Hydrolysis (lipase) reverses this.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Describe the lock-and-key vs induced-fit models of enzyme action.', 'Lock-and-key: rigid active site complementary to substrate. Induced-fit: enzyme changes shape on binding, gripping the substrate and straining bonds, lowering Ea. Induced fit better explains how a single enzyme accommodates similar substrates and catalysis.', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Describe the fluid-mosaic model of the cell membrane.', 'A bilayer of phospholipids (fluid) studded with proteins (mosaic): channel and carrier proteins, glycoproteins / glycolipids for cell signalling and recognition, cholesterol regulating fluidity. Hydrophilic heads outwards, hydrophobic tails inwards.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Compare diffusion, facilitated diffusion, osmosis and active transport.', 'Diffusion: passive, down a gradient, no protein. Facilitated diffusion: passive, via channel/carrier proteins. Osmosis: passive movement of water down a water-potential gradient. Active transport: ATP-driven against the gradient via carrier proteins.', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Describe the cardiac cycle (~0.8 s).', 'Atrial systole: atria contract, AV valves open, ventricles fill (0.1 s). Ventricular systole: AV valves close (lub), ventricles contract, SL valves open, blood ejected (0.3 s). Diastole: SL valves close (dub), all chambers relax, atria refill (0.4 s).', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Outline the formation of an atheroma and its consequences.', 'Damage to endothelium (e.g. by high BP) -> inflammation, white blood cells and lipids accumulate in the artery wall, forming a plaque (atheroma). Narrows lumen, reduces elasticity, raises BP further; rupture causes thrombosis -> heart attack or stroke.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Describe the role of haemoglobin in O2 transport.', 'Quaternary protein with 4 haem groups, each binds one O2. Cooperative binding gives a sigmoidal dissociation curve. High pO2 in lungs -> loads; low pO2 in tissues -> unloads. Bohr shift: high CO2/H+ shifts curve right -> more O2 released.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Compare ventilation in fish and mammals.', 'Fish: water enters mouth, passes over gills (counter-current flow with blood) and out via operculum. Mammals: tidal ventilation by negative pressure (diaphragm and external intercostals contract for inhalation; passive recoil for exhalation).', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'Give the reagents and positive results for biochemical tests for biological molecules.', 'Reducing sugar: Benedict''s, blue -> brick red on heating. Non-reducing: hydrolyse first with HCl. Starch: iodine, yellow -> blue-black. Lipid: emulsion test, white emulsion. Protein: biuret reagent, blue -> purple.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T1', 'Molecules, Transport and Health', 'How can quantitative biochemical tests be performed?', 'Use a colorimeter and a calibration curve. Make a serial dilution of standard solutions, react with the test reagent, measure absorbance at the appropriate wavelength. Plot absorbance against concentration, then read unknown concentration from its absorbance.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Describe the ultrastructure of a eukaryotic cell.', 'Plasma membrane, nucleus (envelope, pore, nucleolus, chromatin), mitochondria (cristae, matrix), RER (with ribosomes), SER, Golgi apparatus (cis/trans), lysosomes, ribosomes (80S), centrioles. Plant cells additionally have chloroplasts, large permanent vacuole, cell wall (cellulose).', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'How are proteins for export packaged and secreted?', 'mRNA is translated on RER ribosomes -> protein enters RER lumen, folded -> vesicles bud off RER -> Golgi modifies (e.g. glycosylation) -> packaged into secretory vesicles -> fuse with plasma membrane (exocytosis).', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Describe the stages of the cell cycle.', 'G1 (cell growth, organelle synthesis) -> S (DNA replication) -> G2 (further growth, error check) -> M (mitosis: PMAT) -> cytokinesis. Checkpoints (e.g. p53) prevent damaged cells progressing.', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'List the differences between mitosis and meiosis.', 'Mitosis: 1 division, 2 diploid daughter cells, identical to parent, used for growth/repair. Meiosis: 2 divisions, 4 haploid daughter cells, genetically distinct (independent assortment, crossing over), used for gamete production.', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Define a stem cell and outline the levels of potency.', 'A stem cell is undifferentiated and can divide repeatedly, giving rise to specialised cells. Totipotent: any cell type incl. extra-embryonic; pluripotent: any body cell; multipotent: limited types (e.g. blood); unipotent: one type.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'How does cell differentiation occur?', 'Cells differentiate by selective gene expression — only certain genes are transcribed and translated, depending on the cell''s position and signals. Transcription factors and epigenetic modifications control which genes are switched on.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Define biodiversity at three levels.', 'Habitat diversity: number of habitats in an area. Species diversity: richness (no. of species) and evenness (relative abundance). Genetic diversity: variety of alleles within a population.', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Calculate Simpson''s index of diversity (D).', 'D = 1 - sum (n / N)^2, where n = no. of individuals of each species, N = total number. Higher D (close to 1) = more diverse and stable; lower D (close to 0) = a few dominant species.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Describe the eight taxonomic ranks and three domains.', 'Domain, Kingdom, Phylum, Class, Order, Family, Genus, Species. Three domains: Bacteria, Archaea, Eukarya — based on molecular evidence (rRNA sequences, membrane lipids).', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'How does DNA / amino acid evidence improve classification?', 'Closely related species share more similar DNA / protein sequences. Direct sequence comparison gives quantitative phylogenetic data, distinguishes convergent evolution, and reveals relationships hidden by morphology.', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'State Darwin''s theory of evolution by natural selection.', '1) Variation exists within a population. 2) More offspring are produced than survive (struggle for existence). 3) Individuals with advantageous alleles are more likely to survive and reproduce. 4) These alleles are passed on, increasing in frequency over generations.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Give two examples of natural selection in action.', 'Antibiotic resistance: random mutation -> survival of resistant bacteria -> fast spread (e.g. MRSA). Peppered moth: dark variants favoured during industrial pollution; light forms favoured after Clean Air Act.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Describe seed banks as a conservation strategy.', 'Seeds are stored at low temperature and humidity (e.g. Millennium Seed Bank), preserving genetic diversity ex situ. Cheaper than habitat conservation; allows re-introduction; useful for crop wild relatives. Limitations: only seed-bearing plants, viability declines over time, requires germination testing.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'Compare in situ and ex situ conservation.', 'In situ: protecting in original habitat (national parks, marine reserves) — preserves ecosystem interactions but vulnerable to disasters. Ex situ: away from the habitat (zoos, seed banks) — controlled, but smaller gene pool and risk of inbreeding.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T2', 'Cells, Development and Biodiversity', 'How are random samples used to assess biodiversity?', 'Use random number coordinates with quadrats / transects to avoid bias. Calculate species frequency, percentage cover and density. Sufficient sample size needed for representative results; combine with statistical tests to compare habitats.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Why do larger animals need specialised exchange surfaces?', 'Surface area : volume falls with size, so simple diffusion cannot meet metabolic needs. Specialised surfaces are large, thin, moist, well-supplied with blood, and ventilated to maintain steep gradients (Fick''s law).', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe gas exchange in mammalian alveoli.', 'Many small alveoli (large total SA ~70 m^2), squamous epithelium one cell thick (short diffusion path), surrounded by capillaries (steep gradient maintained by ventilation and circulation), thin film of fluid for dissolved gases, surfactant lowers surface tension.', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe transpiration and the cohesion-tension theory.', 'Water evaporates from spongy mesophyll into the air spaces and out through stomata. This creates tension in the xylem; cohesion (H-bonds) keeps water as a continuous column, drawn upwards. Adhesion to xylem walls aids capillary action.', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe xylem and phloem structure.', 'Xylem: dead, hollow, lignified tubes (vessels and tracheids); end walls perforated -> continuous tube; pits allow lateral water movement. Phloem: living sieve tube elements (no nucleus, sieve plates) and companion cells (mitochondria, ribosomes -> support sieve tubes via plasmodesmata).', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe how a potometer is used to investigate transpiration.', 'Cut shoot underwater, attach to a capillary tube full of water (no air bubble), seal joints with petroleum jelly. Allow to equilibrate, then measure rate of bubble movement (or mass loss) under varying T, light, humidity, wind.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Outline the mass-flow hypothesis of translocation.', 'Sucrose loaded into sieve tubes at the source by H+/sucrose co-transport (active). Water enters by osmosis, raising hydrostatic pressure. Sap flows down the pressure gradient to the sink, where sucrose is unloaded and used or stored.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Compare arteries, veins and capillaries.', 'Arteries: thick muscular and elastic walls, narrow lumen, carry blood at high pressure away from the heart. Veins: thin walls, wide lumen, valves prevent backflow at low pressure. Capillaries: one-cell-thick endothelium, very narrow, large total SA, sites of exchange.', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe formation of tissue fluid.', 'At the arteriole end, hydrostatic pressure > oncotic pressure -> fluid (without proteins) is forced out. At the venule end, hydrostatic pressure has dropped while oncotic pressure (proteins remain) draws water back in. Excess returns via lymph.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Compare sexual and asexual reproduction.', 'Sexual: gametes fuse, offspring genetically variable (meiosis, fertilisation), beneficial in changing environments. Asexual: one parent, offspring identical, fast and energy-efficient, beneficial in stable environments. Many plants use both (vegetative propagation + flowers).', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe gametogenesis in mammals.', 'Spermatogenesis: in seminiferous tubules; spermatogonia divide by mitosis -> primary spermatocytes -> meiosis -> spermatids -> mature sperm. Oogenesis: oogonia in fetal ovary -> primary oocytes (meiosis I arrested at birth) -> resume per cycle, completing meiosis II only at fertilisation.', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe fertilisation in mammals.', 'Acrosome reaction: enzymes from sperm head digest zona pellucida. Sperm membrane fuses with oocyte. Cortical reaction prevents polyspermy. Sperm nucleus enters; meiosis II completes; fusion of male and female pronuclei -> diploid zygote.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe the structure and function of the placenta.', 'Chorionic villi increase SA for exchange between maternal and fetal blood (which never mix). Glucose, amino acids, O2, antibodies cross to the fetus; CO2, urea, hormones cross from fetus to mother. The placenta also secretes hCG, oestrogen and progesterone.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Outline pollination and double fertilisation in flowering plants.', 'Pollen lands on stigma -> pollen tube grows down style. Two male nuclei pass down: one fuses with the egg -> diploid zygote (embryo); the other fuses with two polar nuclei -> triploid endosperm (food store). This is double fertilisation.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'Describe seed dispersal mechanisms.', 'Wind (e.g. dandelion, sycamore wings), water (coconut), animal (sticky burrs, edible fruits with hard seed coat), explosive (peas, geranium). Dispersal reduces competition with parent plant and colonises new habitats.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T3', 'Exchange, Transport and Reproduction', 'How does a xerophyte minimise water loss?', 'Thick waxy cuticle, sunken / hairy stomata (still air, raises humidity), rolled leaves, reduced leaf SA (spines), fewer stomata, deep roots, CAM photosynthesis (open stomata at night).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Write the overall photosynthesis equation and identify oxidation/reduction.', '6CO2 + 6H2O -> C6H12O6 + 6O2. CO2 is reduced to glucose (gain of H, electrons); H2O is oxidised to O2. Light energy supplied via chlorophyll.', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Outline the light-dependent reactions.', 'Photolysis at PSII: 2H2O -> 4H+ + 4e- + O2. Excited e- pass down ETC, pumping H+ into thylakoid lumen. Chemiosmosis: H+ drives ATP synthase. NADP+ + H+ + 2e- -> NADPH. Cyclic photophosphorylation produces only ATP.', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Describe the Calvin cycle.', 'CO2 + RuBP (5C) -> 2 GP (3C) (catalysed by RuBisCO). GP reduced to TP using ATP and NADPH. Some TP forms glucose; most regenerates RuBP using ATP. Six turns yield one glucose.', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'How do varying CO2, light and temperature affect photosynthesis?', 'Each acts as a limiting factor when in shortest supply. Low light: rate is light-limited. High light, low CO2: rate plateaus, CO2 limits. Below optimum T: enzymes slow. Above optimum: enzymes denature; rate drops sharply.', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'List the four stages of aerobic respiration and their locations.', 'Glycolysis (cytoplasm), link reaction (mitochondrial matrix), Krebs cycle (matrix), oxidative phosphorylation / ETC (inner mitochondrial membrane).', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Describe the link reaction and Krebs cycle.', 'Link: pyruvate -> acetyl (2C) + CO2 + NADH; combined with CoA. Krebs: acetyl-CoA + 4C -> 6C; decarboxylation/dehydrogenation give 2 CO2, 3 NADH, 1 FADH2 and 1 ATP per turn (x2 per glucose).', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Explain how chemiosmosis generates ATP.', 'NADH/FADH2 deliver e- to the ETC, pumping H+ into the intermembrane space. The H+ gradient (proton motive force) drives H+ back into matrix through ATP synthase, phosphorylating ADP -> ATP. O2 is final e- acceptor (-> H2O).', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Compare anaerobic respiration in animals and yeast.', 'Animals: pyruvate + NADH -> lactate + NAD+. Reversible; lactate cleared in liver (oxygen debt). Yeast: pyruvate -> ethanal + CO2 -> ethanol + NAD+. Both regenerate NAD+ to allow glycolysis to continue without O2.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Define an ecosystem and describe energy flow in a food chain.', 'Ecosystem: biotic community + abiotic environment, interconnected by energy and nutrient cycles. Energy enters as light, captured by producers (NPP), then passes to herbivores and carnivores. Loss at each trophic level: respiration, heat, faeces -> typically ~10% transfer.', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Define succession and describe primary succession.', 'Directional change in community over time. Primary: bare rock -> pioneer species (lichens) -> mosses -> herbs -> shrubs -> woodland (climax). Each stage modifies abiotic environment (soil, light) for the next.', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Outline the carbon cycle.', 'Photosynthesis fixes CO2 into organic compounds. Respiration, combustion and decomposition return CO2 to the atmosphere. Carbon is stored in living biomass, soil, fossil fuels and oceans (HCO3-). Anthropogenic burning of fossil fuels increases atmospheric CO2.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Describe the role of saprobionts in decomposition.', 'Saprobionts (e.g. fungi, bacteria) secrete extracellular enzymes onto dead matter (extracellular digestion). Soluble products are absorbed. They release ammonium ions, beginning the nitrogen cycle, and CO2 by respiration.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Describe aseptic technique for culturing microorganisms.', 'Sterilise loop in a Bunsen flame, work near the flame to create an updraft, lift agar lid only briefly. Inoculate, replace lid, tape lightly (allow O2). Incubate at <25 °C in schools, sealed, to prevent pathogens. Autoclave waste.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'Compare batch and continuous fermentation.', 'Batch: nutrients added once, products accumulate; reactor cleaned between runs. Useful for secondary metabolites (penicillin). Continuous: nutrients added and product removed throughout; ideal for primary metabolites (e.g. enzymes), more efficient.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T4', 'Energy, Environment and Microbiology', 'How is bacterial growth measured and described mathematically?', 'Optical density (turbidity) or viable counts (serial dilution + colony count) per ml. Phases: lag, log (exponential), stationary, decline. Log: N = N0 x 2^n, where n is number of generations.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Describe semi-conservative DNA replication.', 'Helicase unwinds the helix; H-bonds break. Free DNA nucleotides align with their complement on each parental template. DNA polymerase joins them by phosphodiester bonds (5''-3''). Each daughter molecule has one parental and one new strand. Meselson-Stahl confirmed this.', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Outline transcription and post-transcriptional modification.', 'Gene unwinds; RNA polymerase joins free RNA nucleotides to a template strand (U replaces T). Pre-mRNA undergoes splicing in the nucleus: introns are removed; exons are joined. A 5'' cap and poly-A tail are added before mRNA leaves through nuclear pores.', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Describe translation step by step.', 'mRNA binds the small ribosomal subunit; tRNA carrying methionine binds the start codon AUG. Next tRNA (anticodon complementary to next codon) binds; peptide bond forms. Ribosome translocates one codon along; first tRNA leaves. Continues to a stop codon.', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Define silent, missense, nonsense, frameshift and large-scale mutations.', 'Silent: same amino acid (degenerate code). Missense: different amino acid. Nonsense: codon -> STOP, truncated protein. Frameshift: insertion/deletion shifts reading frame. Large-scale: duplication, inversion, translocation of chromosome regions.', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Describe a monohybrid and a dihybrid cross.', 'Mono: Aa x Aa -> 3:1 dominant:recessive. Di: AaBb x AaBb -> 9:3:3:1 (assuming no linkage). Use Punnett squares to predict ratios; chi-squared tests if observed differs significantly from expected.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Explain codominance and incompatible blood groups.', 'In the ABO system: I^A and I^B alleles are codominant (both expressed in heterozygotes -> AB blood). I^O is recessive. Genotypes: I^A I^A or I^A I^O = A; I^B I^B or I^B I^O = B; I^A I^B = AB; I^O I^O = O.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Describe sex linkage with haemophilia.', 'Allele on X chromosome (X^h, recessive). Females need two X^h to be affected; one X^h makes a carrier. Males are hemizygous (X^h Y) -> affected. Hence haemophilia much more common in males.', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Explain epistasis with Labrador coat colour.', 'B (black) is dominant to b (brown). Locus E controls deposition: E_ allows pigment, ee blocks it -> yellow regardless of B. Recessive epistasis: ee masks the B locus.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'State and apply the Hardy-Weinberg equations.', 'Allele frequencies p + q = 1 (where p = dominant, q = recessive). Genotype frequencies p^2 + 2pq + q^2 = 1. Assumes large population, random mating, no migration/mutation/selection. e.g. if q^2 = 0.04, q = 0.2, p = 0.8.', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Describe directional, stabilising and disruptive selection.', 'Directional: extreme phenotype favoured (e.g. peppered moths in soot). Stabilising: intermediate favoured (e.g. human birth weight). Disruptive: both extremes favoured, often the precursor to speciation.', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Compare allopatric and sympatric speciation.', 'Allopatric: geographical isolation -> different selection pressures and mutations -> reproductive isolation. Sympatric: arises in the same area (polyploidy in plants, behavioural / temporal isolation), without a physical barrier.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Describe the role of isolation mechanisms in speciation.', 'Pre-zygotic: behavioural, mechanical, temporal, gametic. Post-zygotic: hybrid inviability, hybrid sterility (e.g. mules). Once gene flow stops, allele frequencies diverge until interbreeding is no longer possible.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'How is artificial selection (selective breeding) applied?', 'Choose individuals with desired traits, breed them, select again from offspring; repeat over generations. Examples: high milk yield in dairy cattle, disease-resistant crops. Reduces genetic diversity -> vulnerable to disease and environmental change.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'Describe the use of statistical tests in genetics (chi-squared).', 'Used to compare observed and expected ratios in genetic crosses. chi^2 = sum ((O - E)^2 / E). Compare to critical value at appropriate degrees of freedom (categories - 1) at p = 0.05. If chi^2 > critical, deviation is significant.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T5', 'Genetics and Evolution', 'How do humans drive evolution (e.g. antibiotic resistance)?', 'Overuse / underuse of antibiotics imposes selection pressure on bacteria. Resistant mutants survive and reproduce, spreading resistance genes (sometimes via plasmids, horizontal transfer). Result: emergence of MRSA, multi-drug-resistant TB.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Compare bacterial, viral, fungal and protoctist diseases with examples.', 'Bacterial: TB (M. tuberculosis). Viral: HIV. Fungal: athlete''s foot (Tinea pedis); plant — black sigatoka. Protoctist: malaria (Plasmodium). Each kills cells, releases toxins, or hijacks host machinery.', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Outline non-specific (innate) defences.', 'Skin barrier; mucous membranes trap pathogens; lysozyme in tears/saliva; stomach acid; ciliated epithelia move mucus. Phagocytosis by neutrophils/macrophages. Inflammation: histamine -> vasodilation, increased permeability. Fever raises body T to inhibit pathogens.', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Describe phagocytosis.', 'Phagocyte chemotaxes towards pathogen, recognises by receptors, engulfs by endocytosis -> phagosome. Lysosomes fuse with phagosome -> phagolysosome; hydrolytic enzymes (lysozyme) digest the pathogen. Antigens may be displayed on surface (APC).', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Compare T helper, T killer and B cells.', 'T helper: bind to antigens on APCs, release cytokines that stimulate B cells, T killer cells, and macrophages. T killer: directly kill infected/cancerous cells via perforin and granzymes. B cells: clonally selected, divide into plasma cells (antibodies) and memory cells.', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Describe antibody structure and function.', 'Y-shape; two heavy + two light chains, constant and variable regions, two antigen-binding sites. Functions: agglutinate pathogens, opsonise (mark for phagocytosis), neutralise toxins, activate complement.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Compare primary and secondary immune responses.', 'Primary: slow lag (~5-10 days), low antibody peak; person may show symptoms; produces memory cells. Secondary: faster, larger antibody peak, may not cause symptoms — basis of long-term immunity.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Distinguish active, passive, natural and artificial immunity.', 'Active: own antibodies, memory long-lasting. Passive: given antibodies, no memory, short-term. Natural: through normal life (infection / mother''s milk). Artificial: vaccines (active) or antibody injection (passive, e.g. anti-tetanus).', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Outline how vaccines work and herd immunity.', 'Vaccines contain weakened/dead pathogens or antigens, triggering primary response and producing memory cells. On future infection, secondary response is rapid. Herd immunity: when enough of the population is vaccinated, pathogen cannot spread, protecting unvaccinated individuals.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'How does antibiotic resistance evolve?', 'Mutations giving resistance (e.g. modified target, beta-lactamase) arise randomly. Antibiotics select for resistant bacteria. Resistant mutants reproduce; resistance genes spread vertically and horizontally (plasmid conjugation). Misuse and incomplete courses accelerate this.', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Describe how time of death is estimated.', 'Body temperature: ~1.5 °C drop per hour for 12 hours (algor mortis). Rigor mortis: stiffening from ~2 h, peaks at 12 h, fades by 36 h (Ca2+ accumulates, no ATP). Hypostasis (livor mortis): blood pooling, fixed by ~12 h. Insect succession on body. Stomach contents.', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'How is time since death estimated using insects (forensic entomology)?', 'Different insect species colonise a body in succession (blowflies first, then beetles). Egg/larval/pupal stages have known development times at given temperatures, allowing investigators to estimate post-mortem interval.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Outline DNA profiling using STRs.', 'Extract DNA, amplify short tandem repeat (STR) regions by PCR, separate fragments by gel/capillary electrophoresis. Each individual has a near-unique combination of repeat lengths -> banding pattern. Used in identification, paternity testing, forensics.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Describe gel electrophoresis principles.', 'DNA fragments are loaded into wells in agarose; an electric field pulls negatively charged DNA towards the anode. Smaller fragments move further. Bands are visualised with UV after staining (e.g. ethidium bromide). Compared to a marker / reference ladder.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'Outline polymerase chain reaction (PCR).', 'Cycles of 95 °C (denature), ~55 °C (anneal primers), 72 °C (extend with Taq polymerase). Each cycle doubles the DNA: after n cycles, 2^n copies. Used in DNA profiling, diagnostics and gene cloning.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T6', 'Immunity, Infection and Forensics', 'How does HIV cause AIDS?', 'HIV is a retrovirus binding CD4 on T helper cells; reverse transcriptase makes DNA copy of viral RNA, integrating into host genome. After latency, virus replicates and destroys T helpers. Loss of immunity -> opportunistic infections (TB, pneumonia) and Kaposi''s sarcoma -> AIDS.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Define homeostasis and explain why it is essential.', 'The maintenance of a stable internal environment within tolerance limits despite external change. Stable T, pH, blood glucose and water potential keep enzymes active and cells functional, allowing optimum metabolism.', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Describe negative feedback with an example.', 'A change away from set point triggers a response that reverses it. e.g. blood glucose rises -> beta cells secrete insulin -> liver/muscle take up glucose, blood glucose falls. Distinct from positive feedback (amplifies change, e.g. oxytocin in childbirth).', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Distinguish CNS and PNS, somatic and autonomic.', 'CNS = brain + spinal cord. PNS = sensory + motor neurones outside CNS. Somatic = voluntary control of skeletal muscle. Autonomic = involuntary control of smooth muscle, cardiac muscle and glands; subdivided into sympathetic (fight/flight) and parasympathetic (rest/digest).', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Explain a resting potential.', 'Na+/K+ pump moves 3 Na+ out and 2 K+ in per ATP. K+ leak channels allow K+ to diffuse out, leaving the inside ~-70 mV relative to outside. Maintained by ATP and selective membrane permeability.', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Sketch and label an action potential.', 'Stimulus opens voltage-gated Na+ channels (depolarisation, -70 -> +40 mV). Na+ channels close, K+ channels open (repolarisation). Hyperpolarisation as K+ overshoots; Na+/K+ pump restores resting potential. Refractory period prevents overlap.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Describe synaptic transmission at a cholinergic synapse.', 'AP arrives -> depolarisation opens Ca2+ channels in presynaptic membrane -> Ca2+ enters -> vesicles fuse with membrane and release ACh. ACh binds receptors on postsynaptic membrane, opening Na+ channels -> EPSP. Acetylcholinesterase removes ACh.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Compare temporal and spatial summation.', 'Temporal: one presynaptic neurone fires repeatedly so neurotransmitter accumulates -> threshold reached. Spatial: several presynaptic neurones release simultaneously -> threshold reached at a single postsynaptic neurone.', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Describe how insulin reduces blood glucose.', 'Beta cells in islets of Langerhans detect rising blood glucose; insulin released. Activates tyrosine kinase receptors on liver/muscle/adipose cells -> more GLUT4 vesicles inserted -> increased glucose uptake; glycogenesis activated; lipogenesis stimulated.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Explain the second-messenger model of glucagon.', 'Alpha cells release glucagon when blood glucose falls. Glucagon binds receptor on liver -> activates G-protein -> adenylyl cyclase -> cAMP (second messenger) -> PKA -> phosphorylates glycogen phosphorylase -> glycogenolysis -> glucose released to blood.', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Compare type 1 and type 2 diabetes.', 'Type 1: autoimmune destruction of beta cells (no insulin) -> insulin injections needed. Type 2: insulin resistance / reduced secretion; managed with diet, exercise, metformin. Type 2 risk factors: obesity, age, family history, inactivity.', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Describe thermoregulation in mammals.', 'Hypothalamus monitors blood T. Too cold: vasoconstriction, shivering, hair erected (insulating layer), thyroxine release. Too hot: vasodilation, sweating, hair flattens. Behavioural responses (seek shade, change posture) supplement physiological control.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Describe ultrafiltration in the nephron.', 'Glomerulus: high BP forces small molecules through fenestrated capillaries, basement membrane (selective barrier) and slits between podocytes into Bowman''s capsule. Blood cells and large proteins remain in the blood.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Describe selective reabsorption in the proximal convoluted tubule.', 'Microvilli give large SA. Na+ pumped out into blood by Na+/K+ pumps; Na+ re-enters with glucose / amino acids by co-transport. Glucose then enters blood by facilitated diffusion. Water follows osmotically.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Explain the loop of Henle and counter-current multiplier.', 'Descending limb: permeable to water but not ions; water leaves into the medulla (which has low water potential). Ascending limb: impermeable to water; Na+/Cl- actively pumped out. Creates a salt gradient in the medulla allowing water reabsorption from the collecting duct.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Outline ADH control of water balance.', 'High blood solute concentration -> osmoreceptors in hypothalamus stimulate posterior pituitary to release ADH -> binds collecting duct receptors -> aquaporins inserted -> more water reabsorbed -> small volume of concentrated urine.', 15, 'alevel'),
  ('Biology', 'Edexcel A', 'T7', 'Homeostasis and Response', 'Describe the sliding filament theory of muscle contraction.', 'AP arrives at neuromuscular junction -> Ca2+ released from sarcoplasmic reticulum binds troponin, moving tropomyosin to expose binding sites on actin. Myosin heads bind actin -> power stroke (ADP/Pi released). New ATP binds, head detaches; ATP -> ADP+Pi resets head.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Outline how transcription factors control gene expression.', 'TFs bind specific promoter / enhancer sequences and either recruit (activators) or block (repressors) RNA polymerase. They are made in response to internal/external signals, ensuring only relevant genes are transcribed in a given cell type.', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Explain how oestrogen activates transcription.', 'Lipid-soluble oestrogen diffuses through the plasma membrane and binds an intracellular receptor (TF). The complex enters the nucleus, binds hormone response elements on DNA, and stimulates transcription of target genes.', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Distinguish DNA methylation and histone modification (epigenetics).', 'DNA methylation: -CH3 added to cytosine (usually CpG islands), typically silences transcription. Histone acetylation: loosens DNA-histone binding -> easier transcription. Methylation of histones can either activate or silence depending on residue. Reversible and inheritable.', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'How do siRNAs and miRNAs regulate gene expression?', 'Short non-coding RNAs base-pair with complementary mRNA. siRNA usually triggers cleavage by RISC; miRNA usually inhibits translation. Reduce protein production from a specific gene.', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Describe how restriction enzymes cut DNA.', 'Restriction endonucleases recognise specific palindromic sequences (e.g. EcoRI: GAATTC) and cut, leaving sticky or blunt ends. Sticky ends are complementary single-stranded overhangs which allow fragments from different sources to be joined.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Outline gene cloning using a bacterial plasmid.', 'Cut gene and plasmid with the same restriction enzyme -> complementary sticky ends. DNA ligase joins gene into plasmid -> recombinant DNA. Plasmid taken up by host bacterium (CaCl2 + heat shock). Marker genes identify successful uptake.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Describe the polymerase chain reaction (PCR).', 'Cycles: 95 °C denature, ~55 °C anneal primers, 72 °C extend with Taq polymerase. Each cycle doubles DNA: 2^n copies after n cycles. Used in cloning, sequencing and DNA profiling.', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Describe how to make recombinant insulin.', 'Reverse transcriptase converts insulin mRNA from human pancreas to cDNA. Sticky ends added (RE) and ligated into a plasmid vector. E. coli host transformed; selected with antibiotic-resistance markers. Bacteria cultured; insulin extracted and purified.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Compare somatic and germline gene therapy.', 'Somatic: alters body cells of an individual (e.g. CFTR delivered to lung cells in CF) — not heritable. Germline: alters egg/sperm/embryo so the change is passed on; banned in humans for ethical reasons.', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Outline CRISPR-Cas9 gene editing.', 'A guide RNA matches the target DNA sequence; Cas9 nuclease cuts both strands. The cell repairs the break, either by error-prone NHEJ (knock-out) or by homology-directed repair using a donor template (precise edit).', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Describe DNA sequencing by Sanger / dideoxy method.', 'Mix template DNA, primer, polymerase, dNTPs and small amounts of fluorescently labelled ddNTPs. Each ddNTP terminates extension. Capillary electrophoresis separates fragments by size and detects the colour of the terminator -> read off the sequence.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Outline the use of GMOs in agriculture (Bt crops, golden rice).', 'Bt crops: contain a gene from Bacillus thuringiensis encoding an insecticidal toxin -> reduces pesticide use. Golden rice: engineered with vitamin A precursor (beta-carotene) genes to combat deficiency in developing countries.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Describe how a fermenter can be optimised for a microbial product.', 'Maintain optimum T (water jacket), pH (buffers), O2 (sparger), nutrient concentration. Stir to keep contents uniform. Sterilise to prevent contamination. Continuous flow for primary metabolites; batch for secondary metabolites.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Describe immobilised enzymes and one advantage.', 'Enzyme is bound to or trapped within a solid support (alginate beads, gel, membrane). Reusable, easier product separation, more stable to T/pH. Used in industrial processes (glucose isomerase, lactose-free milk).', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'T8', 'Gene Expression and Biotechnology', 'Describe the use of DNA microarrays in genomics.', 'Thousands of single-stranded DNA probes are fixed to a slide. Sample DNA / cDNA is fluorescently labelled and hybridises to complementary probes. A scanner detects which probes light up -> shows which genes are present or expressed.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Describe CP1: effect of caffeine on Daphnia heart rate.', 'Place a Daphnia in a cavity slide with pond water; locate heart under low power. Count beats over 10 s. Repeat in pond water with varied [caffeine]; allow acclimation. Plot rate vs concentration. Ethics: minimise time out of water; avoid lethal concentrations.', 1, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Outline CP2: vitamin C content by DCPIP titration.', 'DCPIP is decolourised by ascorbic acid. Titrate vitamin C standard into a fixed DCPIP volume to find volume needed to decolourise -> calibration. Repeat with juice. Compare volumes inversely (less juice needed = higher [vitamin C]).', 2, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Describe CP3: membrane permeability of beetroot at varied temperatures.', 'Cut equal beetroot cylinders, rinse to remove leaked pigment. Place in tubes of distilled water at varying T (5-80 °C). After fixed time, remove, measure absorbance of red leakage at ~470 nm using a colorimeter. Higher absorbance -> more disrupted membrane.', 3, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Outline CP4: enzyme activity vs substrate concentration.', 'Use catalase (yeast or liver) with varied [H2O2]. Measure O2 produced (gas syringe) per unit time. Plot rate vs [H2O2]: rate rises and plateaus when active sites are saturated (Vmax). Control: T, pH, [enzyme].', 4, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Describe CP6: rate of water uptake using a potometer.', 'Cut shoot underwater (avoid air bubbles) and seal in capillary tube of water with petroleum jelly. Time the bubble moving a set distance. Vary humidity, T, light, wind. Reset bubble using reservoir tap. Repeat for reliable means.', 5, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Outline CP7: zones of inhibition with antimicrobials.', 'Spread bacteria on agar plate (aseptic technique near a Bunsen). Place paper discs soaked in different antimicrobials. Incubate <25 °C. Measure clear zones of inhibition (diameter or area). Larger zone = greater antimicrobial activity. Control: solvent only disc.', 6, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Describe CP8: investigating photosynthesis with Cabomba / Elodea.', 'Submerge pondweed in NaHCO3 solution (CO2 source). Vary light intensity (lamp distance) or wavelength (filters). Count bubbles per minute or use a gas syringe. Plot rate vs intensity (1/d^2 follows inverse square law). Control T, [CO2], pH.', 7, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Outline CP9: respiration rate using a respirometer.', 'Place germinating peas in a sealed tube with KOH (absorbs CO2); manometer fluid level moves as O2 is consumed. Use thermostatically controlled bath. Control: glass beads (no respiration). Calculate volume of O2 used per unit time per gram.', 8, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Describe CP13: DNA extraction from a plant (e.g. onion).', 'Mash onion in salt + detergent buffer (detergent dissolves membranes, salt clumps DNA). Filter, then add cold ethanol gently to top of solution -> DNA precipitates as a white "candy floss" at the interface. Pick out with a glass rod.', 9, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Outline CP14: effect of temperature on enzyme rate.', 'Use catalase + H2O2 (or amylase + starch). Set up water baths at 0-80 °C. Mix enzyme and substrate at temperature; measure rate (gas/colour change). Plot rate vs T: optimum then sharp drop above due to denaturation.', 10, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Describe CP15: estimating populations using sampling techniques.', 'Random sampling: random coordinates with quadrats -> mean density. Systematic: line/belt transect across an environmental gradient. Mark-release-recapture for mobile organisms: N = (n1 x n2) / m. Calculate Simpson''s index for diversity.', 11, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Outline CP16: phototropism / gravitropism investigation.', 'Grow seedlings (e.g. cress) in different light conditions: unilateral light, no light, all-around light. Measure curvature; observe positive phototropism in shoots and negative phototropism in roots. Control: T, water, support.', 12, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'How is a calibration curve created and used?', 'Make standards of known concentration; measure their response (absorbance / intensity). Plot calibration curve. Measure unknown sample under the same conditions and read its concentration off the line. Always include a blank for zeroing.', 13, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Distinguish between continuous and discontinuous data and choose a graph.', 'Continuous: any value within a range (height) -> line graph / scatter. Discontinuous: distinct categories or whole numbers (eye colour, counts) -> bar chart. Histograms used for continuous data grouped into classes.', 14, 'alevel'),
  ('Biology', 'Edexcel A', 'CP', 'Core Practicals', 'Describe how to calculate the standard deviation and why use it.', 'sigma = sqrt(sum((x - mean)^2) / (n - 1)). Quantifies the spread of data around the mean. Smaller sigma -> data more reproducible. Used with t-tests to assess whether sample means differ significantly.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare single, double and closed circulatory systems.', 'Single (e.g. fish): blood passes through the heart once per circuit; gill -> body. Double (mammals): twice per circuit (pulmonary + systemic), maintaining higher pressures. Closed: blood remains within vessels (mammals); open (insects): haemolymph bathes tissues.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe a single cardiac cycle.', 'Atrial systole: atria contract, AV valves open, ventricles fill. Ventricular systole: AV valves close (lub), ventricles contract, SL valves open, blood ejected. Diastole: SL valves close (dub), all chambers relax, atria refill. Cycle ~0.8 s at 75 bpm.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare arteries, veins and capillaries.', 'Arteries: thick muscular wall, narrow lumen, elastic, carry oxygenated blood (except pulmonary) at high pressure. Veins: thin wall, wide lumen, valves prevent backflow at low pressure. Capillaries: one cell thick endothelium, narrow, large total SA -> exchange.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Why is water described as a polar molecule?', 'O is more electronegative than H, creating a partial negative charge on O and partial positives on H. Water molecules form hydrogen bonds, giving high specific heat capacity, latent heat of vaporisation, cohesion, and excellent solvent properties.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Distinguish saturated, monounsaturated and polyunsaturated fatty acids.', 'Saturated: no C=C, straight chain, solid (animal fats). Monounsaturated: one C=C; polyunsaturated: 2+ C=C, kinked chains -> oils, liquid. cis/trans isomerism affects health: trans fats raise LDL.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare HDL and LDL.', 'LDL (low-density): transports cholesterol from liver to tissues; high LDL contributes to atheromas. HDL (high-density): returns cholesterol from tissues to liver. A high HDL : LDL ratio is associated with reduced cardiovascular disease risk.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe the formation of an atheroma and its consequences.', 'Damage to endothelium -> inflammation; LDL and white blood cells accumulate in the artery wall, forming a fibrous plaque (atheroma). Lumen narrows; elasticity falls; BP rises; plaque rupture -> thrombosis -> heart attack or stroke.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'List CVD risk factors and how each contributes.', 'Genetics, age, gender. Modifiable: high BP, high LDL, smoking (CO reduces O2 capacity, nicotine raises BP), diet (saturated/trans fats, salt), inactivity, obesity, diabetes. Each damages endothelium or alters blood lipids.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Define correlation vs causation, and identify confounding variables.', 'Correlation: two variables vary together. Causation: one variable directly produces the change in the other. Confounding variables: a third factor that affects both (e.g. age, smoking). Studies must control these to identify true causation.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Compare cohort and case-control studies.', 'Cohort: a group is followed forward in time, recording outcomes (lung cancer in smokers vs non-smokers). Case-control: starts with cases (lung cancer patients) and controls, looks back at exposures (smoking). Cohort is stronger evidence but slower.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe the structure of haemoglobin and oxygen binding.', 'Quaternary protein: 4 polypeptide subunits (2 alpha, 2 beta), each with a haem group containing Fe2+ that binds one O2. Cooperative binding gives a sigmoidal dissociation curve.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Explain the Bohr effect.', 'Increased CO2 / H+ in active tissue lowers pH, reducing haemoglobin''s affinity for O2. The dissociation curve shifts right, so more O2 is unloaded where it is most needed.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Describe how cholesterol-lowering treatments work.', 'Statins inhibit HMG-CoA reductase -> less cholesterol synthesis in the liver. Anti-platelet drugs (aspirin) reduce clot risk. Antihypertensives (ACE inhibitors, beta blockers, diuretics) lower BP. Plant stanols competitively inhibit cholesterol absorption.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Define risk and probability and calculate from data.', 'Risk = probability of an event = number of events / total. Relative risk = exposure group risk / unexposed risk. e.g. if smokers'' risk = 0.2, non-smokers'' = 0.05, RR = 4 -> 4-fold higher risk.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S1', 'Lifestyle, Health and Risk', 'Outline how lifestyle interventions reduce CVD risk.', 'Stop smoking, reduce saturated/trans fats and salt, increase fruit/veg/fibre, exercise regularly, maintain healthy BMI, moderate alcohol. These lower BP and LDL, improve insulin sensitivity, and reduce inflammation.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe the structure of DNA.', 'A nucleotide = phosphate + deoxyribose + base (A, T, C or G). Polynucleotide strands joined by phosphodiester bonds. Two antiparallel strands held by H-bonds: A=T (2), G≡C (3). Twisted into a right-handed double helix.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Compare DNA in eukaryotes vs prokaryotes.', 'Eukaryotic DNA: linear, in nucleus, wound around histones, has introns and exons. Prokaryotic DNA: circular, in cytoplasm (nucleoid), no histones, no introns. Plasmids may also be present.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline the genetic code.', 'Triplet, non-overlapping, degenerate, universal. Start codon AUG; three stop codons. With 4 bases x 3 positions = 64 codons coding 20 amino acids -> redundancy reduces effects of mutation.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe transcription and post-transcriptional modification.', 'RNA polymerase joins free RNA nucleotides to a template strand (U replaces T) -> pre-mRNA. Splicing removes introns; exons rejoin. 5'' cap and poly-A tail added. Mature mRNA exits via nuclear pore.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe translation in detail.', 'Small ribosomal subunit binds mRNA; tRNA carrying methionine binds AUG; large subunit completes ribosome. Next tRNA binds complementary codon; peptide bond forms. Ribosome translocates one codon. Continues until a stop codon -> polypeptide released.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe types of gene mutations and outcomes.', 'Substitution: silent / missense / nonsense. Insertion or deletion: frameshift -> all subsequent amino acids changed. Effect depends on protein function: e.g. sickle-cell anaemia (substitution Glu -> Val in beta-globin) and CF (delta F508 deletion).', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline cystic fibrosis at the molecular level.', 'Mutation in the CFTR gene (chr 7) — most commonly delta F508. CFTR is a chloride channel. Faulty channel -> thick mucus in airways, gut, reproductive system. Treatments target symptoms (physiotherapy, mucolytics) and the cause (CFTR modulators, gene therapy).', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe how cystic fibrosis is inherited.', 'Autosomal recessive: two cf alleles needed (one from each parent). Carriers (Cc) show no symptoms. Two carriers x: 1/4 affected, 1/2 carriers, 1/4 unaffected. Genetic counselling and prenatal testing available.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe phospholipid bilayer structure.', 'Two layers of phospholipids: hydrophilic phosphate heads point outward (towards aqueous); hydrophobic fatty acid tails point inward. The membrane is fluid; cholesterol regulates fluidity; proteins are embedded as channels, carriers and receptors.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Compare diffusion, facilitated diffusion, osmosis and active transport.', 'Diffusion: passive, lipid-soluble or gases, no protein. Facilitated diffusion: passive via channel/carrier proteins. Osmosis: passive water movement down water-potential gradient. Active transport: against gradient, ATP-driven by carrier proteins.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe how Na+ and Cl- normally cross airway epithelium and how CF disrupts this.', 'Normal: Cl- ions move out through CFTR channels into mucus; Na+ follows; water follows osmotically -> thin watery mucus. CF: faulty CFTR -> Cl- cannot leave; Na+ moves into cell instead; water leaves mucus -> thick sticky mucus.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe the structure of the lungs and gas exchange.', 'Trachea -> bronchi -> bronchioles -> alveoli (~300 million; ~70 m^2). Alveoli: thin squamous epithelium, surrounded by capillaries (also one cell thick), surfactant lining, ventilated by breathing -> O2 diffuses to blood, CO2 diffuses out.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline the role of cilia and goblet cells.', 'Goblet cells secrete mucus that traps pathogens and dust. Ciliated epithelial cells beat to move mucus up to the throat where it is swallowed (mucociliary escalator). Smoking paralyses cilia -> chronic cough.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Describe pre-natal genetic testing for CF (CVS and amniocentesis).', 'CVS (10-13 weeks): biopsy of chorionic villi, faster, slightly higher miscarriage risk (~1%). Amniocentesis (15-20 weeks): sample of amniotic fluid containing fetal cells; lower miscarriage risk (~0.5%) but later. PCR / genetic analysis of CFTR gene.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S2', 'Genes and Health', 'Outline ethical considerations of genetic testing.', 'Benefits: informed reproductive choices, treatment planning. Issues: psychological impact, insurance discrimination, privacy, potential for selective termination, parental disagreements, mis-diagnosis. Pre-test counselling is essential.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe the eukaryotic cell cycle.', 'G1: cell growth, organelle replication. S: DNA replication. G2: further growth, error check. M: mitosis (PMAT). Cytokinesis. Checkpoints (G1/S, G2/M, spindle) prevent damaged cells progressing.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline the four stages of mitosis.', 'Prophase: chromosomes condense (sister chromatids visible), nuclear envelope breaks down, centrosomes move to poles. Metaphase: chromosomes line up on equator. Anaphase: spindle pulls sister chromatids to poles. Telophase: nuclear envelopes reform.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Compare mitosis and meiosis.', 'Mitosis: 1 division, 2 diploid identical daughter cells, growth/repair. Meiosis: 2 divisions, 4 haploid genetically distinct gametes, with independent assortment and crossing over. Source of variation -> evolution.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe two sources of genetic variation in meiosis.', 'Independent assortment: homologous chromosomes line up randomly in metaphase I (and sister chromatids in metaphase II). Crossing over: in prophase I, non-sister chromatids exchange DNA at chiasmata, forming new allele combinations.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Define totipotent, pluripotent, multipotent and unipotent.', 'Totipotent: any cell type incl. extra-embryonic (e.g. zygote). Pluripotent: any embryonic cell type (e.g. embryonic stem cells). Multipotent: limited types (e.g. haematopoietic stem cells). Unipotent: one type (e.g. cardiac muscle progenitor).', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline how stem cells differentiate.', 'Differentiation results from selective gene expression. Specific TFs activate cell-type-specific genes; epigenetic changes (DNA methylation, histone modification) silence others. Position-dependent signals (morphogens) and the cells'' microenvironment guide specialisation.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline benefits and ethical issues of using human embryonic stem cells.', 'Benefits: pluripotent -> potential regenerative therapies (Parkinson''s, spinal injury). Ethics: destruction of embryos; iPS cells offer an alternative with fewer concerns. Strict regulation (HFEA in the UK).', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe how genes and environment interact.', 'Genotype sets potential; phenotype is the result of gene expression + environment. e.g. height (genetic potential limited by nutrition); MZ twins'' methylomes drift over time; many traits are polygenic and multifactorial.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Compare continuous and discontinuous variation.', 'Continuous: range of values (height, mass), polygenic and influenced by environment, normal distribution. Discontinuous: distinct categories (blood group), usually one or few genes, environment little effect; bar chart distribution.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe cell signalling and gene expression.', 'Signal molecule (e.g. hormone) binds a receptor -> transduction (often a phosphorylation cascade) -> activates TFs that bind DNA, switching specific genes on/off. Allows tissue-specific responses.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline mammalian fertilisation.', 'Sperm acrosome reaction: enzymes digest zona pellucida. Sperm membrane fuses with oocyte. Cortical reaction prevents polyspermy. Sperm nucleus enters; meiosis II completes; haploid pronuclei fuse -> diploid zygote. Cleavage starts.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Compare mitochondrial DNA inheritance to nuclear DNA.', 'Mitochondrial DNA is inherited only from the mother (sperm mitochondria are destroyed in zygote). Useful in tracing maternal lineage; mutations linked to several rare diseases.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Outline how the placenta supports the fetus.', 'Maternal and fetal blood are separated by chorionic villi (large SA, thin walls). Glucose, amino acids, O2 and antibodies cross to the fetus; CO2, urea, hormones cross from fetus to mother. Placenta also secretes hCG, oestrogen, progesterone.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'Describe positional information and gradients in development.', 'Concentrations of morphogens (e.g. retinoic acid, Hox transcription factors) form gradients along the embryo, instructing cells about their position and which genes to express. Different thresholds give different fates.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S3', 'Voice of the Genome', 'How are chromosomes packaged in the nucleus?', 'DNA wraps around 8 histone proteins to form a nucleosome (~146 bp). Nucleosomes coil into a 30 nm fibre and fold into chromatin. Heterochromatin (densely packed) silences genes; euchromatin (open) is transcribed.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Outline the eight taxonomic ranks and three domains.', 'Domain, Kingdom, Phylum, Class, Order, Family, Genus, Species. Three domains (Woese): Bacteria, Archaea, Eukarya — based on rRNA sequences, membrane lipids, and genome organisation.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Define a species and describe two ways to define it.', 'Phylogenetic: shared evolutionary lineage on a tree of life. Biological: members can interbreed to produce fertile offspring. Issues: hybrid sterility (mules), asexual species, ring species. Modern molecular comparisons supplement morphology.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'How are molecular methods used to classify organisms?', 'Direct DNA / amino acid sequence comparison gives quantitative similarity. Closer relatives share more conserved sequences. Confirms or revises classifications based on morphology and reveals evolutionary relationships hidden by convergent evolution.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Define biodiversity at three levels.', 'Habitat: number of habitats in an area. Species: richness (count) and evenness (relative abundance). Genetic: variety of alleles within a population. All three vary independently and matter for ecosystem stability.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Calculate Simpson''s index of diversity.', 'D = 1 - sum (n / N)^2, where n = individuals of each species and N = total. D ranges 0-1; higher = more diverse and stable. Sensitive to both richness and evenness.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Define endemism and give an example.', 'A species found only in a single restricted area. e.g. lemurs (Madagascar), Galapagos finches. Endemic species are vulnerable to extinction because their entire range can be affected by a single disturbance.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe the structure of plant cell walls.', 'Cellulose microfibrils (beta-1,4 glucose) crosslinked by hemicellulose and embedded in pectin. Lignin adds strength to xylem and sclerenchyma. Plasmodesmata link cells. The wall provides support, shape and tensile strength against turgor pressure.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Compare xylem and phloem.', 'Xylem: dead, lignified tubes carrying water/minerals from root to leaves; mass flow driven by transpiration tension. Phloem: living sieve tubes with companion cells, transports assimilates (sucrose) from sources to sinks by mass flow.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Outline the cohesion-tension theory of water transport.', 'Water evaporates from spongy mesophyll into air spaces and out via stomata. Tension is created in xylem; H-bonds keep water as a continuous column. Adhesion to xylem walls aids capillary action.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe plant defences against herbivores and pathogens.', 'Physical: thorns, waxy cuticle, hairs (trichomes), thick cell walls. Chemical: tannins (deter feeding), alkaloids (caffeine, nicotine — toxic to insects), terpenoids, antimicrobial proteins. Some defences are induced (jasmonic acid pathway).', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'How are plants used in medicine? (Drug discovery)', 'Examples: aspirin from willow bark salicylates, taxol from yew (cancer), digitalis from foxglove (heart). Bioprospecting screens biodiverse regions; loss of biodiversity means losing potential drugs.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe testing of new drugs (William Withering / clinical trials).', 'Withering used systematic patient observation to determine the correct dose of digitalis. Modern trials: pre-clinical (cells, animals), Phase I (safety in healthy volunteers), II (efficacy), III (large randomised trial vs placebo or current treatment), IV (post-market surveillance).', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Compare in situ and ex situ conservation.', 'In situ: protect species in natural habitat (national parks, reserves) — preserves ecological interactions but vulnerable to disasters. Ex situ: zoos, seed banks, botanical gardens — controlled but smaller gene pool, risk of inbreeding.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Describe a seed bank.', 'Stores dried, low-T seeds (e.g. Millennium Seed Bank, Kew) ex situ. Long-term storage preserves genetic diversity, crop wild relatives, and species at risk of extinction. Limitations: only seed-bearing plants, viability declines, periodic germination tests required.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S4', 'Biodiversity and Natural Resources', 'Outline how zoos contribute to species conservation.', 'Captive breeding programmes (e.g. Arabian oryx, giant panda); coordinated international stud books prevent inbreeding; reintroduction projects; education and research. Critics raise concerns about welfare and habitat loss being the root problem.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Write the photosynthesis equation and identify oxidation/reduction.', '6CO2 + 6H2O -> C6H12O6 + 6O2 (sunlight). CO2 is reduced (gains H/electrons) to glucose. H2O is oxidised to O2 in photolysis at PSII.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Outline the light-dependent reactions.', 'Photolysis at PSII: 2H2O -> 4H+ + 4e- + O2. Excited e- pass down ETC, pumping H+ into thylakoid lumen -> ATP via chemiosmosis. NADP+ + H+ + 2e- -> NADPH. Cyclic photophosphorylation produces only ATP.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe the Calvin cycle.', 'CO2 + RuBP -> 2 GP (catalysed by RuBisCO). GP reduced to TP using ATP and NADPH. Some TP forms hexose; most regenerates RuBP using ATP. Six turns yield one glucose.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe how light, CO2 and temperature affect photosynthesis.', 'Each can be a limiting factor when in shortest supply. Low light: rate limited by photolysis. Low CO2: rate limited by Calvin cycle. Below optimum T: enzymes slow; above ~30 °C: RuBisCO denatures, stomata close.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Define an ecosystem and give an example food chain.', 'Ecosystem = community of organisms + their abiotic environment. Energy enters via producers (NPP), passes to herbivores (primary consumers), to carnivores (secondary), and to top predators. ~10% transfer between levels typical.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Define and calculate net primary productivity (NPP).', 'GPP = total chemical energy fixed by producers per area per time. NPP = GPP - R (respiration). Units: kJ m^-2 yr^-1. NPP is energy available to next trophic level.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe the carbon cycle.', 'Photosynthesis fixes CO2 into organic compounds; respiration, combustion and decomposition return CO2. Carbon stored in biomass, soil, oceans (HCO3-), fossil fuels. Anthropogenic CO2 (fossil fuel burning, deforestation) increases atmospheric levels.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'List evidence for climate change.', 'Direct: ice core CO2 / temperature records, atmospheric CO2 measurements (Mauna Loa), satellite data, sea-level rise, glacier retreat. Indirect: dendrochronology, pollen analysis, isotope ratios in foraminifera. Multiple independent lines converge on warming.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Explain how rising temperatures affect species distribution.', 'Species shift poleward and upward in altitude as temperatures rise; phenological mismatches (flowering vs pollinators) occur; range contractions if no migration possible (e.g. mountain-top species). Loss of habitat and mismatched timing reduce reproductive success.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe primary succession from bare rock.', 'Pioneer species (e.g. lichens) colonise bare rock, weather it and add organic matter. Mosses follow, then small plants, grasses, shrubs and finally woodland (climax). Each stage modifies the abiotic conditions for the next.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Compare deflected and secondary succession.', 'Secondary: starts on existing soil after disturbance (e.g. fire); succession proceeds as for primary but faster. Deflected: human activity (mowing, grazing) holds the community at an earlier seral stage (heathland, chalk grassland) — often biodiverse.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'State Hardy-Weinberg principle and equations.', 'Allele frequencies stay constant across generations if: large population, no migration, no mutation, no selection, random mating. p + q = 1; p^2 + 2pq + q^2 = 1.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Describe natural selection in peppered moths and antibiotic resistance.', 'Peppered moth: dark form favoured during industrial pollution (camouflage on sooty trees); light form returns after Clean Air Act. Antibiotic resistance: random mutations in bacteria; resistant variants survive antibiotic treatment and reproduce.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'Compare allopatric and sympatric speciation.', 'Allopatric: geographical isolation -> divergent selection / drift -> reproductive isolation. Sympatric: arises within a population without a physical barrier (polyploidy in plants, behavioural / temporal isolation).', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S5', 'On the Wild Side', 'How can we mitigate climate change biologically?', 'Reduce CO2 emissions (fossil fuel substitution, energy efficiency); reforestation and afforestation; rewetting peatlands; protect oceans (blue carbon); reduce deforestation; carbon capture and storage; soil management. Both supply-side and demand-side action needed.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Compare types of pathogens and give one example each.', 'Bacteria: prokaryote, peptidoglycan wall (e.g. TB Mycobacterium tuberculosis). Virus: nucleic acid + capsid, hijacks host (HIV). Fungi: eukaryote, hyphae (athlete''s foot Trichophyton). Protoctist: eukaryote (Plasmodium - malaria).', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe non-specific (innate) defences.', 'Skin barrier; mucous membranes; lysozyme in tears/saliva; gastric acid; ciliated epithelia; phagocytosis (neutrophils, macrophages); inflammation (histamine, vasodilation); fever (raised T inhibits pathogens). Fast but non-specific.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe phagocytosis step-by-step.', 'Phagocyte chemotaxes towards pathogen, recognises by surface receptors, engulfs by endocytosis -> phagosome. Lysosomes fuse with phagosome -> phagolysosome; lysozyme digests pathogen. Antigens displayed on MHC for T-cell activation.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Compare T helper, T killer and B cells.', 'T helper: bind APCs, release cytokines that activate other cells. T killer: directly kill infected/cancer cells (perforin, granzymes). B cells: differentiate into plasma cells (antibodies) or memory cells once selected by their specific antigen.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe antibody structure and four functions.', 'Y-shape, two heavy + two light chains, constant + variable regions, two antigen-binding sites. Functions: agglutination, opsonisation (mark for phagocytosis), neutralisation of toxins, activation of complement.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Compare primary and secondary immune responses.', 'Primary: slow lag, low antibody peak, may show symptoms. Memory cells form. Secondary: rapid (hours), high antibody peak, often asymptomatic. Forms the basis of long-term immunity.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe vaccination and herd immunity.', 'Vaccines contain weakened/inactivated pathogens or antigens, triggering primary response and memory cells without disease. If many in a population are immune, the pathogen cannot spread (herd immunity), protecting unvaccinated individuals.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Distinguish active, passive, natural and artificial immunity.', 'Active: own antibodies / memory (long-term). Passive: received antibodies (short-term). Natural: through life (infection / breast milk). Artificial: vaccines (active) or antibody injection (passive, e.g. anti-tetanus).', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'How do antibiotics work?', 'Bactericidal: kill bacteria (penicillin disrupts peptidoglycan synthesis -> weak walls -> lysis). Bacteriostatic: prevent growth (tetracyclines block 70S ribosomes -> halt protein synthesis). Selective toxicity: target features absent in human cells.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'How does antibiotic resistance evolve?', 'Random mutation gives resistance (e.g. beta-lactamase, modified penicillin-binding proteins). Antibiotics select for resistant strains; resistance genes spread via plasmid conjugation (horizontal transfer). Misuse and incomplete courses accelerate this.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe how time of death is estimated.', 'Algor mortis: ~1.5 °C drop per hour (first 12 h). Rigor mortis: stiffness from ~2 h, peak at 12 h, fades by 36 h. Hypostasis (livor): blood pooling, fixed by ~12 h. Insect succession (entomology). Stomach contents.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Outline DNA profiling using STRs.', 'Extract DNA, amplify short tandem repeat (STR) regions by PCR, separate fragments by gel/capillary electrophoresis. Each individual has a near-unique STR profile -> banding pattern. Used in identification, paternity, forensics.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Outline polymerase chain reaction (PCR).', 'Cycles: 95 °C denature -> ~55 °C anneal primers -> 72 °C extend with Taq polymerase. Each cycle doubles DNA -> 2^n copies after n cycles. Used in cloning, sequencing and DNA profiling.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Describe how decomposers contribute to nutrient cycling.', 'Saprobionts (fungi, bacteria) secrete extracellular enzymes onto dead matter; soluble products absorbed by diffusion. Detritivores fragment material. Resulting NH4+ enters the nitrogen cycle; CO2 returns to atmosphere via respiration.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S6', 'Immunity, Infection and Forensics', 'Outline forensic uses of mtDNA.', 'mtDNA is inherited maternally and present in many copies per cell -> retrievable from old / degraded samples (bone, hair shaft) where nuclear DNA is unrecoverable. Compared with maternal relatives to identify remains (e.g. Romanovs).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'List the four stages of aerobic respiration with location.', 'Glycolysis (cytoplasm), link reaction (matrix), Krebs cycle (matrix), oxidative phosphorylation (inner mitochondrial membrane / cristae).', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Outline glycolysis.', 'Glucose phosphorylated using 2 ATP -> hexose bisphosphate -> 2 triose phosphate. Each TP oxidised to pyruvate; net 2 ATP and 2 NADH per glucose. Anaerobic; in cytoplasm.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe the link reaction and Krebs cycle.', 'Link: 2 pyruvate -> 2 acetyl-CoA, 2 NADH and 2 CO2. Krebs (x2): each acetyl-CoA + 4C -> 6C; decarboxylation/dehydrogenation give 2 CO2, 3 NADH, 1 FADH2 and 1 ATP per turn (per glucose: 4 CO2, 6 NADH, 2 FADH2, 2 ATP).', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Explain oxidative phosphorylation by chemiosmosis.', 'NADH/FADH2 deliver e- to ETC on inner membrane. Electrons pass between carriers, pumping H+ into intermembrane space. H+ flows back through ATP synthase -> ATP. O2 final acceptor: O2 + 4H+ + 4e- -> 2H2O.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Compare lactate and ethanol fermentation.', 'Animals: pyruvate + NADH -> lactate + NAD+; reversible (lactate cleared in liver -> oxygen debt). Yeast/plants: pyruvate -> ethanal + CO2 -> ethanol + NAD+; irreversible. Both regenerate NAD+ to allow glycolysis to continue.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Compare slow- and fast-twitch muscle fibres.', 'Slow-twitch (Type I): aerobic, many mitochondria, lots of myoglobin, fatigue-resistant (postural muscles, marathon). Fast-twitch (Type II): anaerobic glycolysis, large glycogen and phosphocreatine stores, fatigue quickly (sprinting, weightlifting).', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe the structure of a sarcomere.', 'Region between two Z-lines. Contains overlapping thin actin and thick myosin filaments. I-band: actin only. A-band: full length of myosin. H-zone: myosin only (no actin). M-line: middle of sarcomere. Sarcomere shortens during contraction.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Outline the sliding filament theory.', 'AP arrives at NMJ -> Ca2+ released from sarcoplasmic reticulum -> Ca2+ binds troponin, moving tropomyosin to expose actin binding sites. Myosin heads bind actin -> power stroke (ADP/Pi released). New ATP binds, head detaches; ATP -> ADP+Pi resets.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe how heart rate is controlled.', 'SAN sets pace -> wave of depolarisation across atria -> AVN delays -> Bundle of His -> Purkyne fibres -> ventricles contract from apex up. Medulla regulates rate via sympathetic (accelerator) and parasympathetic (vagus) nerves; baroreceptors and chemoreceptors feed back.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'How does exercise affect ventilation?', 'CO2 produced in respiration lowers blood pH; chemoreceptors in aortic / carotid bodies detect this and signal medulla -> increases breathing rate and depth. Stretch receptors in lungs prevent over-inflation. After exercise, debt repaid by elevated breathing.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Define VO2 max and how it adapts to training.', 'Maximum rate of O2 uptake during intense exercise (mL kg^-1 min^-1). Reflects cardiovascular and respiratory efficiency. Aerobic training raises VO2 max via increased stroke volume, capillary density, mitochondria and myoglobin in muscle.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe role of the kidneys in osmoregulation.', 'Ultrafiltration in glomerulus; selective reabsorption in PCT; loop of Henle establishes a salt gradient in the medulla; ADH-controlled water reabsorption in collecting duct. Maintains constant blood water potential during exercise / dehydration.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Outline thermoregulation during exercise.', 'Increased respiration produces heat. Hypothalamus detects rise; vasodilation of skin arterioles, sweating (evaporative cooling), reduced metabolic heat. After exercise: shivering or vasoconstriction may follow if body T overshoots.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe how performance-enhancing drugs work and ethical issues.', 'Anabolic steroids: mimic testosterone -> increased muscle synthesis; risks include heart damage and infertility. EPO: boosts red blood cells -> O2 carriage; risk of clots. Stimulants: mask fatigue. Ethics: unfair advantage, health risk, role-model effect, legality.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S7', 'Run for Your Life', 'Describe the keyhole / arthroscopic surgery for sports injury.', 'A small incision allows a fibre-optic camera and instruments into a joint. Cartilage tears are trimmed or repaired; ACL reconstruction uses graft tissue. Less tissue trauma -> faster recovery than open surgery, though possible complications (infection, stiffness).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe the structure of a typical neurone.', 'Cell body (with nucleus), dendrites (receive signals), axon (conducts AP), and axon terminals (release neurotransmitter). Axon may be myelinated by Schwann cells (PNS) or oligodendrocytes (CNS), with nodes of Ranvier.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Distinguish CNS and PNS, somatic and autonomic, sympathetic and parasympathetic.', 'CNS = brain + spinal cord. PNS: sensory + motor neurones. Somatic: voluntary skeletal muscle. Autonomic: involuntary smooth/cardiac muscle/glands. Sympathetic: fight/flight; parasympathetic: rest/digest.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Explain the resting potential.', 'Na+/K+ pump moves 3 Na+ out / 2 K+ in per ATP. K+ leaks out via leak channels, leaving inside ~-70 mV relative to outside. Maintained by ATP and selective membrane permeability.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Sketch and label an action potential.', 'Stimulus -> threshold (-55 mV) -> voltage-gated Na+ channels open (depolarisation to +40 mV). Na+ channels close, K+ channels open (repolarisation). Hyperpolarisation; Na+/K+ pump restores resting potential.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Why does myelination speed transmission?', 'Myelin (Schwann/oligodendrocyte) is electrically insulating. Action potentials only occur at unmyelinated nodes of Ranvier; the impulse "jumps" between nodes (saltatory conduction), much faster than continuous conduction.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe synaptic transmission at a cholinergic synapse.', 'AP arrives -> Ca2+ channels open, Ca2+ enters -> vesicles fuse with membrane and release ACh. ACh diffuses across cleft, binds postsynaptic receptors, opens Na+ channels. Acetylcholinesterase hydrolyses ACh; choline recycled.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe excitatory and inhibitory postsynaptic potentials.', 'EPSP: depolarising (Na+ entry) — moves potential towards threshold. IPSP: hyperpolarising (Cl- entry or K+ exit) — moves it away. Summation of EPSPs and IPSPs determines whether the postsynaptic neurone fires.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe the major regions of the human brain and their functions.', 'Cerebrum: voluntary action, learning, memory. Cerebellum: balance, coordination. Hypothalamus: homeostasis, thermoregulation. Pituitary: hormones. Medulla: heart and breathing centres.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Outline how the eye detects light.', 'Light passes cornea, pupil, lens (focuses), vitreous humour, hits retina. Rods (rhodopsin, peripheral, dim light) and cones (3 types, fovea, colour) generate AP -> bipolar cells -> ganglion cells -> optic nerve. Image processed in visual cortex.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Compare rods and cones.', 'Rods: high sensitivity (many to one bipolar -> retinal convergence); monochromatic; rhodopsin; concentrated outside fovea. Cones: low sensitivity, high acuity (1:1 to bipolar); iodopsin (3 colour types); concentrated in fovea.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Outline learning and types of memory.', 'Sensory -> short-term -> long-term (consolidation). Habituation: decreased response to a repeated harmless stimulus (sea-slug Aplysia). Classical and operant conditioning. Memories stored across synapses; LTP strengthens connections.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe how drugs affect synapses (e.g. nicotine, MDMA, L-DOPA).', 'Nicotine: agonist of nicotinic ACh receptors -> stimulation; reward via dopamine. MDMA: floods synapses with serotonin (release + reuptake inhibition). L-DOPA: precursor of dopamine, crosses BBB to relieve Parkinson''s symptoms.', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Describe the symptoms and cause of Parkinson''s disease.', 'Loss of dopaminergic neurones in the substantia nigra. Symptoms: tremor, rigidity, bradykinesia, postural instability. Treatments: L-DOPA, dopamine agonists, MAO-B inhibitors, deep brain stimulation. Causes: idiopathic, genetic factors, environmental.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Outline the imaging techniques: CT, MRI, fMRI, PET.', 'CT: X-ray slices -> structural images. MRI: magnetic field aligns nuclei -> high-resolution structural images, no ionising radiation. fMRI: detects blood-O2 changes (BOLD signal) -> activity. PET: radiolabelled tracers -> functional metabolism.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'S8', 'Grey Matter', 'Compare nature and nurture in shaping the brain.', 'Genes provide the basic neural framework (e.g. innate reflexes). Environment shapes synaptic connections, particularly in critical periods (e.g. visual deprivation in kittens). Both interact: brain plasticity allows learning throughout life.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP1: investigating effect of temperature on enzyme activity (amylase).', 'Use buffered amylase + starch at varying T (water baths). At intervals, sample on a tile with iodine -> note when iodine remains yellow (starch fully digested). Rate = 1/time. Optimum ~37 °C; activity falls sharply above as enzymes denature.', 1, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP2: cell fractionation.', 'Homogenise tissue in cold (slows enzymes), isotonic (prevents osmotic damage), buffered solution. Filter, then centrifuge at increasing speeds: pellets in order — nuclei -> chloroplasts -> mitochondria -> lysosomes -> ER -> ribosomes.', 2, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP3: investigating osmosis in plant tissue.', 'Cut equal-mass potato cylinders. Place in solutions of varied [sucrose]. After fixed time, blot, reweigh. % change in mass plotted against [sucrose]. Where mass change = 0, the potato''s water potential equals that of the surrounding solution.', 3, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP4: caffeine on Daphnia heart rate.', 'Place a Daphnia on a slide with pond water; locate heart under low power. Count beats over 10 s. Repeat with varied [caffeine]; allow acclimation. Plot rate vs concentration. Ethics: minimise distress.', 4, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP5: membrane permeability of beetroot at varied T.', 'Cut equal cylinders, rinse off leaked pigment. Place in distilled water at varied T (0-80 °C). Measure absorbance of leaked betacyanin in colorimeter (~470 nm). Higher absorbance -> more disrupted membrane.', 5, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP7: rate of water loss from a leaf.', 'Use a potometer or weighed leaves under controlled conditions. Vary humidity / wind / light. Monitor mass loss / bubble movement over time. Plot rate against IV; control all other factors.', 6, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP8: antimicrobial properties of plants.', 'Test extracts of garlic, mint, etc. on bacterial lawn (aseptic technique near a Bunsen). Place soaked discs onto agar. Incubate <25 °C. Measure zone of inhibition (diameter or area). Larger zone = greater antimicrobial activity.', 7, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP9: photosynthesis rate using Elodea.', 'Submerge pondweed in NaHCO3 solution (CO2 source). Vary light intensity (lamp distance) or wavelength (filters). Count bubbles per minute or use a gas syringe. Plot rate vs intensity. Control T, [CO2], pH.', 8, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP10: respiration rate using a respirometer.', 'Place germinating peas in a sealed tube with KOH (CO2 absorber); manometer fluid level moves as O2 consumed. Use thermostatically controlled bath. Control: glass beads. Calculate V(O2) per unit time per gram.', 9, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP11: effect of exercise on ventilation.', 'Measure breathing rate and depth at rest. Exercise (steady cycle / step) for 3-5 min; measure during recovery. Plot ventilation rate vs time. Use a peak-flow meter or spirometer for tidal volume. Control fitness level and rest period.', 10, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP12: plant tropism investigation.', 'Grow seedlings (e.g. cress) in different light conditions: unilateral light, dark, all-around light. Measure curvature of stems and roots. Positive phototropism in shoots; negative phototropism in roots. Control: T, water, type of seed.', 11, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP13: investigating genetic variation in a population.', 'Choose a continuously varying trait (height, hand span). Sample 30+ individuals; record measurements. Plot a histogram and calculate mean and SD. Continuous data tend to be normally distributed (polygenic + environmental influences).', 12, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Outline CP14: estimating biodiversity using sampling techniques.', 'Random sampling: random coordinates with quadrats. Systematic: line/belt transect. Calculate species richness and Simpson''s index of diversity D = 1 - sum(n/N)^2. Use mark-release-recapture for mobile organisms.', 13, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'Describe CP15: DNA extraction from a plant (onion).', 'Mash onion in salt + detergent (lyses membranes). Filter. Add cold ethanol gently to top -> DNA precipitates as a white "candy floss" at the interface. Collect with a glass rod.', 14, 'alevel'),
  ('Biology', 'Edexcel B', 'CP', 'Core Practicals', 'How is a result evaluated for accuracy and reliability?', 'Accuracy: closeness to true value (compare with literature / reference). Reliability: consistency on repetition (look at SD or range; repeat 5+ times). Consider random and systematic errors; identify limitations and improvements.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Distinguish independent, dependent and control variables.', 'IV: variable manipulated by the experimenter. DV: variable measured. Controls: variables held constant to ensure only the IV affects the DV. Without controls, observed changes can''t be attributed to the IV alone.', 1, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Distinguish accuracy, precision, reliability and validity.', 'Accuracy: closeness to true value. Precision: small spread of repeats. Reliability: results reproduce on repetition. Validity: investigation answers the original question and only the IV affected the DV.', 2, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Define random and systematic errors.', 'Random errors cause scatter (read by repeating and averaging). Systematic errors cause a consistent shift away from the true value (e.g. zero error on a balance) and cannot be reduced by repetition.', 3, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'How is uncertainty estimated for a single reading?', 'For analogue: half the smallest scale division. For digital: ±1 in the last digit. For repeated readings: half the range. Express as absolute and percentage uncertainty.', 4, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Describe how to choose a sample size and sampling method.', 'Larger samples reduce random error. Random sampling: random coordinates / individuals. Systematic: regular intervals (transects). Stratified: groups sampled proportionally. Method depends on whether a gradient or subgroup structure is present.', 5, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Outline how to use a t-test.', 'Used to compare two means of approximately normally distributed samples. Calculate t, find critical value at (n1 + n2 - 2) df, p = 0.05. If t > critical, reject H0 -> significant difference.', 6, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Describe Spearman''s rank correlation.', 'Used to check whether two ranked variables are correlated. r_s = 1 - (6 sum d^2 / n(n^2 - 1)) where d is rank difference. Compare with critical value at n - 2 df. r_s near +1 / -1 = strong positive / negative correlation.', 7, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Describe chi-squared (chi^2) test of goodness of fit.', 'chi^2 = sum ((O - E)^2 / E). Compare to critical value at (categories - 1) df, p = 0.05. If chi^2 > critical, reject H0 -> deviation from expected ratio is significant. Used in genetics, ecology.', 8, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'How is a calibration curve created and used?', 'Make standards of known concentration; measure response (e.g. absorbance). Plot calibration curve. Measure unknown sample under same conditions and read off concentration. Always include a blank for zeroing.', 9, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Outline good aseptic technique.', 'Sterilise loop in flame, work near a Bunsen, lift agar lid only briefly, replace and tape lightly. Incubate <25 °C in schools, sealed. Autoclave waste. Disinfect bench and hands before and after.', 10, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Compare line, bar and histogram graphs.', 'Line graph: continuous IV and DV; show trends over time / concentration. Bar chart: discontinuous (categorical) data; bars don''t touch. Histogram: continuous data grouped into classes; bars touch and area = frequency.', 11, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Describe ethical considerations in biological investigations.', 'Animal research: 3Rs (replacement, reduction, refinement); avoid undue suffering. Human studies: informed consent, anonymity, right to withdraw, ethical approval. Field studies: avoid habitat damage, follow protected-species laws.', 12, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'How are anomalous results identified and treated?', 'Plot data and inspect; values clearly outside the expected range are anomalies. Repeat to check. Exclude from mean calculations but record honestly with reasons. Investigate the source (procedural error, contamination).', 13, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'Describe the use and calculation of standard deviation.', 'sigma = sqrt(sum((x - mean)^2) / (n - 1)). Quantifies spread of data around mean. Smaller sigma -> more precise. Plotted as error bars on bar charts/scatter plots; non-overlapping error bars suggest a real difference.', 14, 'alevel'),
  ('Biology', 'OCR A', 'M1', 'Development of Practical Skills', 'List safety practices for biology practicals.', 'Wear lab coat, safety goggles and gloves where appropriate. Risk-assess procedures (HSE, CLEAPSS). No mouth-pipetting. Sterilise where microorganisms are involved. Use COSHH for hazardous chemicals. Dispose of biological/chemical waste correctly.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'List eukaryotic organelles and their functions.', 'Nucleus: stores DNA, transcription. Mitochondrion: aerobic respiration. RER: protein synthesis/folding. SER: lipid synthesis. Golgi: modifies/packages proteins. Lysosomes: hydrolytic enzymes. Ribosomes (80S): translation. Centrioles: spindle in mitosis. Plant cells additionally have chloroplasts, large vacuole, cellulose cell wall.', 1, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Compare prokaryotes and eukaryotes.', 'Prokaryotes are smaller (~1-5 µm), no nucleus (circular naked DNA), 70S ribosomes, no membrane-bound organelles, peptidoglycan cell wall, may have plasmids, capsule, flagella.', 2, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Compare TEM and SEM electron microscopes.', 'TEM: thin specimen, electrons pass through, very high resolution (~0.2 nm), 2D internal structure. SEM: surface scanned, lower resolution, 3D surface image. Both: vacuum, dead specimens, expensive, prone to artefacts.', 3, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Define magnification, resolution and how an eyepiece graticule is calibrated.', 'Magnification = image / actual; resolution = smallest distance between two distinguishable points. Calibrate using a stage micrometer: 1 division on the eyepiece = how many µm on the stage scale at that objective.', 4, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Why is water described as a polar molecule?', 'Oxygen is more electronegative than hydrogen; the O end is delta-negative and H ends are delta-positive. Water molecules form hydrogen bonds, giving high specific heat capacity, latent heat of vaporisation, cohesion, and excellent solvent properties.', 5, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Describe condensation and hydrolysis reactions.', 'Condensation: two monomers join with the loss of one water molecule (forming glycosidic, peptide or ester bond). Hydrolysis: water is added to break a bond, splitting a polymer into smaller units.', 6, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Describe the four levels of protein structure.', 'Primary: amino acid sequence (peptide bonds). Secondary: alpha helix / beta pleated sheet (H-bonds between C=O and N-H). Tertiary: 3D fold (H-bonds, ionic, disulfide, hydrophobic). Quaternary: 2+ subunits (e.g. haemoglobin: 4 chains + haem).', 7, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Describe a DNA nucleotide and the formation of a polynucleotide.', 'A nucleotide = phosphate + deoxyribose + base (A/T/C/G). Nucleotides join 5'' to 3'' by phosphodiester bonds (condensation), forming a sugar-phosphate backbone. Two antiparallel strands wind into a right-handed double helix held by H-bonds.', 8, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Explain induced-fit enzyme catalysis.', 'Substrate binds the active site; the enzyme subtly changes shape so the active site moulds tightly around the substrate. This places strain on bonds, lowering Ea. Enzyme returns to original shape after products leave.', 9, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'How do competitive and non-competitive inhibitors differ?', 'Competitive: similar shape to substrate, binds active site; effect overcome by raising [substrate]. Non-competitive: binds an allosteric site, distorts the active site so substrate cannot bind; effect not overcome by raising [substrate].', 10, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Describe the fluid-mosaic model.', 'A phospholipid bilayer with proteins (channels, carriers, receptors) embedded in the fluid. Glycoproteins/glycolipids for cell signalling and recognition. Cholesterol regulates fluidity. Hydrophilic heads outwards, hydrophobic tails inwards.', 11, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Compare diffusion, facilitated diffusion, osmosis and active transport.', 'Diffusion: passive, no protein. Facilitated diffusion: passive, via channel/carrier proteins. Osmosis: passive, water down a water-potential gradient. Active transport: ATP-driven, against gradient via carrier proteins.', 12, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Describe the cell cycle stages.', 'G1 (growth, organelle replication) -> S (DNA replication) -> G2 (further growth, error check) -> M (mitosis: PMAT) -> cytokinesis. Checkpoints (G1/S, G2/M, spindle) prevent damaged cells progressing.', 13, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Outline the four stages of mitosis.', 'Prophase: chromosomes condense, nuclear envelope breaks down, centrioles move to poles. Metaphase: chromosomes align on equator. Anaphase: spindle pulls sister chromatids to poles. Telophase: nuclear envelopes reform.', 14, 'alevel'),
  ('Biology', 'OCR A', 'M2', 'Foundations in Biology', 'Compare mitosis and meiosis.', 'Mitosis: 1 division, 2 diploid identical daughter cells, growth/repair. Meiosis: 2 divisions, 4 haploid genetically distinct gametes, with independent assortment and crossing over -> source of genetic variation.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Why do larger organisms need specialised exchange surfaces?', 'Surface area : volume falls with size, so simple diffusion cannot meet metabolic demand. Specialised exchange surfaces are large, thin, moist, well-supplied with blood, and ventilated to maintain gradients (Fick''s law).', 1, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe gas exchange in mammalian alveoli.', 'Many alveoli (large total SA ~70 m^2), squamous epithelium one cell thick (short diffusion path), surrounded by capillaries (gradient maintained), thin film of fluid for dissolved gases, surfactant lowers surface tension.', 2, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe the counter-current exchange in fish gills.', 'Water flows over lamellae in the opposite direction to blood. This maintains a concentration gradient along the entire length of the lamella, so ~80% of dissolved O2 is absorbed (vs ~50% with parallel flow).', 3, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe insect tracheal system.', 'Air enters through spiracles -> tracheae -> tracheoles -> tissues directly. Diffusion is supplemented by ventilation (abdominal pumping) and water moving out of tracheole tips during activity, increasing surface area for diffusion.', 4, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe the human breathing mechanism.', 'Inspiration: diaphragm contracts (flattens), external intercostals contract -> volume up, pressure down -> air flows in. Expiration: muscles relax, elastic recoil -> volume down, pressure up -> air flows out. Forced expiration uses internal intercostals + abdominals.', 5, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe the cardiac cycle.', 'Atrial systole: atria contract, AV valves open, ventricles fill (~0.1 s). Ventricular systole: AV valves close (lub), ventricles contract, SL valves open, blood ejected (~0.3 s). Diastole: SL valves close (dub), all chambers relax, atria refill (~0.4 s).', 6, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe how heart rate is controlled.', 'SAN sets pace -> wave of depolarisation across atria -> AVN delays -> Bundle of His -> Purkyne fibres -> ventricles contract from apex up. Medulla regulates rate via sympathetic and parasympathetic nerves; baro/chemoreceptors feed back.', 7, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Compare arteries, veins and capillaries.', 'Arteries: thick wall, narrow lumen, high pressure, no valves (except SL). Veins: thin wall, wide lumen, low pressure, valves prevent backflow. Capillaries: one cell thick, narrow, large total SA -> exchange.', 8, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe formation of tissue fluid.', 'At the arterial end of a capillary, hydrostatic pressure > oncotic pressure -> fluid forced out. At the venous end, hydrostatic pressure has dropped while oncotic pressure (proteins) draws fluid back in. Excess returns via lymph.', 9, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe the structure and function of haemoglobin.', 'Quaternary protein: 4 polypeptide subunits (2 alpha, 2 beta), each with a haem group containing Fe2+ that binds one O2. Cooperative binding gives a sigmoidal dissociation curve.', 10, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Explain the Bohr effect.', 'Increased CO2 / H+ in active tissue lowers pH, reducing haemoglobin''s affinity for O2; the dissociation curve shifts right. More O2 unloaded where it is most needed. Fetal Hb has higher O2 affinity (curve left of adult).', 11, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'How is CO2 transported in the blood?', '~5% dissolved in plasma; ~10% bound to haemoglobin (carbaminohaemoglobin); ~85% as HCO3- (chloride shift). In RBCs: CO2 + H2O -> H2CO3 -> H+ + HCO3- (catalysed by carbonic anhydrase). H+ binds Hb (buffer).', 12, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Describe xylem and phloem structure.', 'Xylem: dead, lignified, hollow tubes (vessels and tracheids); end walls perforated -> continuous tube. Phloem: living sieve tube elements (no nucleus, sieve plates) and companion cells (mitochondria, ribosomes -> support sieve tubes via plasmodesmata).', 13, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Outline the cohesion-tension theory of water transport.', 'Water evaporates from spongy mesophyll into air spaces and out via stomata (transpiration). Tension in xylem; H-bonds keep water as a continuous column. Adhesion to xylem walls aids capillary action. Roots also push water by root pressure (active uptake of ions).', 14, 'alevel'),
  ('Biology', 'OCR A', 'M3', 'Exchange and Transport', 'Outline the mass-flow hypothesis of translocation.', 'Sucrose loaded into sieve tubes at source by H+/sucrose co-transport -> low water potential. Water enters by osmosis -> high hydrostatic pressure. Sap flows down pressure gradient to sink, where sucrose is unloaded and used or stored.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'List four types of pathogens with examples in plants and animals.', 'Bacteria: TB (M. tuberculosis); ring rot (Clavibacter, plants). Virus: HIV; tobacco mosaic virus (TMV). Fungi: athlete''s foot; black sigatoka (banana). Protoctist: malaria (Plasmodium); potato late blight (Phytophthora).', 1, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'How are pathogens transmitted?', 'Direct: contact, droplet, faecal-oral, sexual. Indirect: vectors (mosquitos, animals), fomites (objects), water, food, soil, vertical (mother to fetus). Plants: wind, water, vectors, soil contact, contaminated tools.', 2, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Describe non-specific (innate) defences in animals.', 'Skin barrier; mucous membranes; lysozyme; gastric acid; ciliated epithelia; phagocytosis (neutrophils, macrophages); inflammation (histamine, vasodilation); fever. Fast but non-specific.', 3, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Outline plant defences.', 'Physical: bark, waxy cuticle, lignified cell walls, callose deposition. Chemical: tannins, alkaloids, terpenoids, antimicrobial proteins, salicylates. Hypersensitive response: localised cell death to limit pathogen spread.', 4, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Describe phagocytosis.', 'Phagocyte chemotaxes towards pathogen, recognises by surface receptors, engulfs by endocytosis -> phagosome. Lysosomes fuse, hydrolytic enzymes (lysozyme) digest the pathogen. Antigens presented on MHC II for T-cell activation.', 5, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Describe roles of T helper, T killer, B and memory cells.', 'T helper: bind APCs, release cytokines that stimulate B cells, T killer cells, macrophages. T killer: kill infected cells (perforin, granzymes). B cells -> plasma cells (antibodies) and memory B cells. Memory T cells maintain long-term immunity.', 6, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Compare primary and secondary immune responses.', 'Primary: slow lag, low antibody peak, may show symptoms; produces memory cells. Secondary: rapid, high antibody peak, often asymptomatic. Forms the basis of long-term immunity.', 7, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Distinguish active, passive, natural and artificial immunity.', 'Active: own antibodies, memory long-term. Passive: given antibodies, no memory, short-term. Natural: through normal life. Artificial: vaccines (active) or antibody injection (passive). e.g. anti-tetanus = artificial passive.', 8, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Describe how vaccines work and herd immunity.', 'Vaccines contain weakened/dead pathogens or antigens, triggering primary response and memory cells without disease. If high enough proportion vaccinated, pathogen cannot spread, protecting unvaccinated (herd immunity). Threshold depends on R0.', 9, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Describe biodiversity at three levels.', 'Habitat: number of habitats. Species: richness (count) + evenness (proportion). Genetic: variety of alleles within a population. All three matter for ecosystem stability and resilience.', 10, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Calculate Simpson''s index of diversity.', 'D = 1 - sum (n / N)^2 where n = number of organisms of each species and N = total. Higher D (close to 1) = more diverse and stable; lower D (close to 0) = a few dominant species.', 11, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Describe the eight taxonomic ranks and three domains.', 'Domain, Kingdom, Phylum, Class, Order, Family, Genus, Species. Three domains (Woese): Bacteria, Archaea, Eukarya — based on rRNA sequences and membrane chemistry.', 12, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Outline Darwin''s theory of natural selection.', '1) Variation within populations. 2) More offspring produced than survive. 3) Individuals with advantageous alleles more likely to survive and reproduce. 4) These alleles become more common over generations -> evolution.', 13, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Give two examples of natural selection.', 'Antibiotic resistance in bacteria: random mutations in resistance genes; antibiotic selection -> resistant strains spread (e.g. MRSA). Peppered moth: dark variants favoured during industrial pollution; light variants favoured after the Clean Air Act.', 14, 'alevel'),
  ('Biology', 'OCR A', 'M4', 'Biodiversity, Evolution and Disease', 'Compare in situ and ex situ conservation.', 'In situ: protect species in natural habitat (national parks). Preserves ecosystem interactions but vulnerable to disasters. Ex situ: zoos, seed banks, botanical gardens. Controlled but smaller gene pool, risk of inbreeding.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Explain the resting potential.', 'Na+/K+ pump moves 3 Na+ out / 2 K+ in per ATP. K+ leak channels allow K+ to diffuse out, leaving inside ~-70 mV relative to outside. Maintained by ATP and selective membrane permeability.', 1, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Sketch and label an action potential.', 'Stimulus opens voltage-gated Na+ channels (depolarisation, -70 -> +40 mV). Na+ channels close, K+ channels open (repolarisation). Hyperpolarisation as K+ overshoots; Na+/K+ pump restores resting potential. Refractory period prevents overlap.', 2, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Why does myelination speed transmission?', 'Myelin (Schwann cells / oligodendrocytes) is electrically insulating. Action potentials only occur at unmyelinated nodes of Ranvier; the impulse "jumps" between nodes (saltatory conduction), much faster than continuous conduction.', 3, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Describe synaptic transmission at a cholinergic synapse.', 'AP arrives -> Ca2+ channels open in presynaptic membrane -> Ca2+ enters -> vesicles fuse with membrane and release ACh. ACh binds postsynaptic receptors, opening Na+ channels. Acetylcholinesterase hydrolyses ACh; choline recycled.', 4, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Compare temporal and spatial summation.', 'Temporal: one presynaptic neurone fires repeatedly so neurotransmitter accumulates -> threshold reached. Spatial: several presynaptic neurones release simultaneously -> threshold reached at a single postsynaptic neurone.', 5, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Define homeostasis and explain why it matters.', 'Maintenance of stable internal environment within tolerance limits. Stable T, pH, blood glucose and water potential keep enzymes active and cells functional. Negative feedback returns conditions to set point; positive feedback amplifies (e.g. childbirth).', 6, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Describe how insulin and glucagon regulate blood glucose.', 'Beta cells release insulin: more GLUT4 transporters -> increased glucose uptake; activates glycogen synthase -> glycogenesis. Alpha cells release glucagon: cAMP second messenger -> phosphorylates glycogen phosphorylase -> glycogenolysis -> glucose released.', 7, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Compare type 1 and type 2 diabetes.', 'Type 1: autoimmune destruction of beta cells -> insulin injections needed. Type 2: insulin resistance / reduced secretion; managed with diet, exercise, metformin. Type 2 risk factors: obesity, age, family history, inactivity.', 8, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Describe ultrafiltration in the nephron.', 'Glomerulus: high BP forces small molecules (water, glucose, ions, urea) through fenestrated capillary, basement membrane (selective barrier) and slits between podocytes into Bowman''s capsule. Blood cells and large proteins remain in blood.', 9, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Describe selective reabsorption in the proximal convoluted tubule.', 'Microvilli give large SA. Na+ pumped into blood by Na+/K+ pumps; Na+ re-enters with glucose / amino acids by co-transport. Glucose then enters blood by facilitated diffusion. Water follows osmotically. ~85% of filtrate reabsorbed here.', 10, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Outline ADH control of water balance.', 'High blood solute concentration -> osmoreceptors in hypothalamus stimulate posterior pituitary to release ADH -> binds collecting duct receptors -> aquaporins inserted -> more water reabsorbed -> small volume of concentrated urine.', 11, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Outline the light-dependent reactions of photosynthesis.', 'Photolysis at PSII: 2H2O -> 4H+ + 4e- + O2. Excited e- pass down ETC, pumping H+ into thylakoid lumen. Chemiosmosis: H+ flows back through ATP synthase -> ATP. NADP+ + H+ + 2e- -> NADPH. Cyclic photophosphorylation produces only ATP.', 12, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Describe the Calvin cycle.', 'CO2 + RuBP (5C) -> 2 GP (3C) (catalysed by RuBisCO). GP reduced to TP using ATP and NADPH. Some TP forms hexose; most regenerates RuBP using ATP. Six turns yield one glucose.', 13, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Describe glycolysis, link reaction and Krebs cycle.', 'Glycolysis (cytoplasm): glucose -> 2 pyruvate, net 2 ATP and 2 NADH. Link (matrix): 2 pyruvate -> 2 acetyl-CoA + 2 CO2 + 2 NADH. Krebs (matrix, x2): 2 CO2, 3 NADH, 1 FADH2, 1 ATP per turn. Per glucose: 4 CO2, 6 NADH, 2 FADH2, 2 ATP.', 14, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Explain oxidative phosphorylation by chemiosmosis.', 'NADH/FADH2 deliver e- to ETC on inner mitochondrial membrane. As electrons pass, H+ pumped to intermembrane space. H+ flows back through ATP synthase -> ATP. O2 final acceptor: O2 + 4H+ + 4e- -> 2H2O. Theoretical yield ~32 ATP per glucose.', 15, 'alevel'),
  ('Biology', 'OCR A', 'M5', 'Communication, Homeostasis and Energy', 'Compare lactate and ethanol fermentation.', 'Animals: pyruvate + NADH -> lactate + NAD+; reversible (lactate cleared in liver -> oxygen debt). Yeast/plants: pyruvate -> ethanal + CO2 -> ethanol + NAD+; irreversible. Both regenerate NAD+ for glycolysis to continue without O2.', 16, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'How is gene expression regulated?', 'Transcription factors (activators / repressors) bind specific promoter sequences and either recruit or block RNA polymerase. siRNA / miRNA destroy mRNA or inhibit translation. Epigenetic modifications (DNA methylation, histone acetylation) control accessibility.', 1, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Outline the lac operon as a prokaryotic example.', 'In E. coli, lacI gene constitutively makes a repressor that binds the operator, blocking RNA polymerase. When lactose is present, allolactose binds the repressor, releasing it from the operator -> RNA polymerase transcribes lacZYA -> beta-galactosidase produced.', 2, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Describe a monohybrid and a dihybrid cross.', 'Mono: Aa x Aa -> 3:1 dominant:recessive. Di: AaBb x AaBb -> 9:3:3:1 (assuming no linkage). Use Punnett squares to predict ratios; chi-squared tests if observed differs significantly from expected.', 3, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Explain codominance and the ABO blood system.', 'I^A and I^B alleles are codominant (both expressed in heterozygotes -> AB blood). I^O is recessive. Genotypes: I^A I^A or I^A I^O = A; I^B I^B or I^B I^O = B; I^A I^B = AB; I^O I^O = O.', 4, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Describe sex linkage with haemophilia.', 'Allele on X chromosome (X^h, recessive). Females need two X^h to be affected; one X^h makes a carrier. Males with X^h Y are hemizygous and affected. Hence haemophilia much more common in males.', 5, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Define epistasis with an example.', 'One gene masks another. Recessive epistasis: ee blocks pigment in Labradors -> yellow regardless of B locus. Dominant epistasis: e.g. Bombay phenotype masks ABO. Distorted ratios (12:3:1, 9:3:4 etc.) reveal epistasis.', 6, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'State the Hardy-Weinberg equations and assumptions.', 'p + q = 1; p^2 + 2pq + q^2 = 1. Assumes large population, random mating, no migration / mutation / selection. Useful for estimating carrier frequencies (e.g. cystic fibrosis).', 7, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Describe directional, stabilising and disruptive selection.', 'Directional: extreme phenotype favoured (e.g. peppered moth). Stabilising: intermediate favoured (e.g. human birth weight). Disruptive: both extremes favoured (often precursor to speciation).', 8, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Compare allopatric and sympatric speciation.', 'Allopatric: geographical isolation -> divergent selection / drift -> reproductive isolation. Sympatric: arises within a population without a physical barrier (polyploidy in plants, behavioural / temporal isolation).', 9, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Describe how restriction enzymes and ligase build recombinant DNA.', 'Restriction endonucleases cut DNA at palindromic sequences, leaving sticky ends. Same enzyme used on the gene and the vector creates complementary ends. DNA ligase forms phosphodiester bonds between them, producing recombinant DNA.', 10, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Outline polymerase chain reaction (PCR).', 'Cycles: 95 °C denature, ~55 °C anneal primers, 72 °C extend with Taq polymerase. Each cycle doubles DNA -> 2^n copies after n cycles. Used in cloning, sequencing and DNA profiling.', 11, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Outline DNA profiling using STRs.', 'Extract DNA, amplify short tandem repeat (STR) regions by PCR, separate fragments by gel/capillary electrophoresis. Each individual has a near-unique STR profile -> banding pattern. Used in identification, paternity, forensics.', 12, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Compare natural and artificial cloning of plants and animals.', 'Plants: vegetative propagation (runners), tissue culture (totipotent cells -> callus -> plantlets). Animals: identical twins (natural); artificial: nuclear transfer (Dolly, somatic cell nuclear transfer); embryo splitting in livestock.', 13, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Describe primary succession from bare rock.', 'Pioneer species (lichens) colonise bare rock, weather it and add organic matter. Mosses follow, then small plants, grasses, shrubs and finally woodland (climax). Each stage modifies the abiotic conditions for the next.', 14, 'alevel'),
  ('Biology', 'OCR A', 'M6', 'Genetics, Evolution and Ecosystems', 'Outline the nitrogen cycle and four key bacteria.', 'Saprobionts decompose proteins -> ammonium (ammonification). Nitrifying bacteria (Nitrosomonas, Nitrobacter) oxidise NH4+ -> NO2- -> NO3-. Nitrogen-fixing bacteria (Rhizobium, Azotobacter) fix N2 -> NH3. Denitrifying bacteria reduce NO3- -> N2 in anaerobic soil.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG1: microscopy and use of an eyepiece graticule.', 'Calibrate eyepiece graticule against a stage micrometer at each magnification: 1 division = ? µm. Mount specimen, focus low power first, refine at high power. Measure cells using calibrated graticule. Calculate magnification and actual size.', 1, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG2: dissection (e.g. heart).', 'Pin out external features, identify chambers and vessels. Cut along septum; observe atria (thinner walls), ventricles (thicker, especially LV), AV and SL valves, papillary muscles and chordae tendineae. Use sharps disposal; wear gloves.', 2, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG3: sampling techniques.', 'Random sampling: random coordinates with quadrats. Systematic: line/belt transect across an environmental gradient. Calculate species frequency, percentage cover, density. Mark-release-recapture: N = (n1 x n2) / m for mobile organisms.', 3, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Outline PAG4: rates of enzyme reactions.', 'Use catalase + H2O2 (gas syringe collects O2) or amylase + starch (iodine end-point on tile). Vary T, pH or [substrate]. Plot rate vs IV. Control: [enzyme], buffers, mixing time.', 4, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG5: colorimetry.', 'Make a serial dilution of standards; react with reagent; measure absorbance with appropriate filter (complement of solution colour). Plot calibration curve. Read unknown concentrations from absorbance. Always include a blank to zero.', 5, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Outline PAG6: chromatography of plant pigments.', 'Grind leaves with sand and propanone. Spot solvent front on chromatography paper, spot pigments, place in solvent. Calculate Rf = distance moved by spot / distance moved by solvent. Compare Rf to known pigments (chlorophyll a, b, carotene, xanthophyll).', 6, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG7: aseptic technique with antimicrobials.', 'Sterilise loop in flame, work near a Bunsen, lift agar lid only briefly. Spread bacterial culture, place soaked discs of antimicrobials. Incubate <25 °C, sealed. Measure clear zones of inhibition (diameter or area). Larger zone = greater activity.', 7, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Outline PAG8: transport in and out of cells.', 'Osmosis: cut equal-mass potato cylinders; place in solutions of varied [sucrose]; measure % mass change. Where mass change = 0, water potential of potato = solution. Membrane permeability: beetroot cylinders at varied T -> measure leaked betacyanin in colorimeter.', 8, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG9: biochemical tests for biological molecules.', 'Reducing sugar: Benedict''s, blue -> brick red. Non-reducing sugar: hydrolyse with HCl, neutralise, then Benedict''s. Starch: iodine, blue-black. Lipids: emulsion test, white emulsion. Protein: biuret, blue -> purple. Always heat for Benedict''s.', 9, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Outline PAG10: investigation using a data logger.', 'Use sensors (e.g. T probe, pH probe, light sensor, O2 sensor) connected to a data logger. Set sample interval and duration. Advantages: high precision, large data sets, real-time monitoring, no observer bias. Output to spreadsheet for graphing.', 10, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG11: factors affecting respiration rate (respirometer).', 'Place germinating peas with KOH (CO2 absorber) in sealed tube; manometer fluid moves as O2 consumed. Use thermostatically controlled bath. Control: glass beads (no respiration). Calculate volume of O2 used per unit time per gram of organism.', 11, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe PAG12: factors affecting photosynthesis.', 'Submerge pondweed (Cabomba/Elodea) in NaHCO3 solution (CO2 source). Vary light intensity (lamp distance) or wavelength (filters). Count bubbles per minute or use a gas syringe. Plot rate vs intensity. Control T, [CO2], pH.', 12, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'How is a serial dilution prepared accurately?', 'Pipette equal volumes (e.g. 1 cm^3) of stock into test tubes. Add equal volumes of solvent (e.g. 9 cm^3 distilled water) to each. Mix between transfers. This creates a 10-fold dilution series. Use a fresh pipette tip each time to prevent cross-contamination.', 13, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'Describe how to use a haemocytometer.', 'A haemocytometer is a calibrated counting chamber. Fill with diluted cell suspension under a coverslip; count cells in a known volume of grid squares. Cells / cm^3 = (mean count per square) / (square volume) x dilution factor.', 14, 'alevel'),
  ('Biology', 'OCR A', 'PAG', 'Practical Activity Groups', 'How is data analysed and a conclusion drawn?', 'Plot graph (line / scatter / bar / histogram); identify pattern. Calculate gradient / rate / mean / SD. Apply statistical test (t-test, chi^2, Spearman) to assess significance at p = 0.05. Conclusion: link data back to hypothesis; consider limitations and improvements.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Define independent, dependent and control variables.', 'IV: variable manipulated by the experimenter. DV: variable measured. Controls: variables held constant to ensure only the IV affects the DV. Without controls, observed changes can''t be attributed to the IV alone.', 1, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Distinguish accuracy, precision, reliability, validity.', 'Accuracy: closeness to true value. Precision: small spread between repeats. Reliability: same results on repetition. Validity: investigation answers the original question and only the IV affected the DV.', 2, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'How are random and systematic errors managed?', 'Random errors: repeat readings and average; use more precise instruments. Systematic errors: zero / calibrate the instrument; use different equipment or method. Repetition cannot reduce systematic errors.', 3, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Describe how to plan a controlled investigation.', 'Identify IV, DV and controls. Choose a measurable, sensitive method. Decide range and number of values; sample size; repeats. Risk assess (CLEAPSS, COSHH). Plan data table and graph. Pre-test or pilot to refine the method.', 4, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'How is uncertainty estimated for a single reading?', 'For analogue: half the smallest scale division. For digital: ±1 in the last digit. For repeated readings: half the range. Express as both absolute and percentage uncertainty.', 5, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Describe how percentage uncertainties combine.', 'Multiplied/divided quantities: add the percentage uncertainties. Powers: multiply by the index. Use to identify which measurement contributes most error and how to improve.', 6, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Outline how to use a t-test.', 'Compares two means of approximately normally distributed samples. Calculate t, find critical value at (n1 + n2 - 2) df, p = 0.05. If t > critical, reject H0 -> means significantly different.', 7, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Describe Spearman''s rank correlation.', 'Used to test whether two ranked variables are correlated. r_s = 1 - (6 sum d^2 / n(n^2 - 1)) where d = rank difference. Compare with critical value at n - 2 df. Values close to +1 / -1 = strong correlation.', 8, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Describe chi-squared (chi^2) goodness of fit.', 'chi^2 = sum ((O - E)^2 / E). Compare to critical value at (categories - 1) df, p = 0.05. If chi^2 > critical, reject H0 -> deviation from expected ratio is significant. Used in genetics, ecology.', 9, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Describe how to calculate and use standard deviation.', 'sigma = sqrt(sum((x - mean)^2) / (n - 1)). Quantifies the spread around the mean. Smaller sigma -> more precise data. Plotted as error bars on bar charts/scatter plots; non-overlapping error bars suggest a real difference.', 10, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'How are anomalous results identified and treated?', 'Plot data and inspect; values clearly outside the expected range are anomalies. Repeat to check. Exclude from mean calculations but record honestly. Investigate the source (procedural error, contamination, instrument issue).', 11, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Describe how a calibration curve is created and used.', 'Make standards of known concentration; measure response (e.g. absorbance). Plot calibration curve. Measure unknown sample under same conditions; read concentration off the line. Always include a blank for zeroing.', 12, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'How are scientific results communicated and referenced?', 'Use SI units, clear axis labels, key, error bars, statistical tests. Reference using Harvard or Vancouver style: cite primary literature. Distinguish your own data from cited claims. Include limitations and improvements.', 13, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'Outline ethical considerations in biological investigations.', 'Animal research: 3Rs (replace, reduce, refine), avoid suffering. Human studies: informed consent, anonymity, right to withdraw, ethical approval. Field studies: avoid habitat damage, follow protected-species laws.', 14, 'alevel'),
  ('Biology', 'OCR B', 'B1', 'Development of Practical Skills', 'List safety practices for biology practicals.', 'Wear lab coat, goggles, gloves where appropriate. Risk assess (HSE, CLEAPSS, COSHH). Aseptic technique near a Bunsen for microorganisms. No mouth-pipetting. Sharps disposal. Autoclave biological waste.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Compare prokaryotic and eukaryotic cells.', 'Prokaryotes: smaller (~1-5 µm), no nucleus, circular naked DNA, 70S ribosomes, no membrane-bound organelles, peptidoglycan wall, may have plasmids/capsule/flagella. Eukaryotes: larger (~10-100 µm), nucleus, linear DNA + histones, 80S ribosomes, membrane-bound organelles.', 1, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Describe the role of the major eukaryotic organelles.', 'Nucleus: stores DNA, transcription. Mitochondrion: aerobic respiration. Chloroplast: photosynthesis. RER: protein synthesis. SER: lipid synthesis. Golgi: modifies/packages proteins. Lysosomes: digestion. Ribosomes (80S): translation.', 2, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Compare TEM and SEM.', 'TEM: thin specimen, electrons pass through, very high resolution (~0.2 nm), 2D internal structure. SEM: surface scanned, lower resolution, 3D surface image. Both: vacuum, dead specimens, prone to artefacts.', 3, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Why is water described as a polar molecule, and how does this give rise to its properties?', 'Oxygen is more electronegative than hydrogen, so the O end is delta-negative and the H ends are delta-positive. Water molecules form hydrogen bonds, giving high specific heat capacity, latent heat of vaporisation, cohesion, and excellent solvent properties.', 4, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Describe how a glycosidic bond forms between two monosaccharides.', 'Two -OH groups react; one H and one OH are removed as water (condensation). The bond is named by the carbon atoms it links, e.g. alpha-1,4 glycosidic in maltose. Hydrolysis (water added) breaks the bond.', 5, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Compare starch, glycogen and cellulose.', 'Starch (alpha-1,4 + 1,6, plant store): amylose helical, amylopectin branched -> compact. Glycogen (alpha, animal store): more highly branched -> rapid hydrolysis. Cellulose (beta-1,4, alternating orientation): straight chains, H-bonded into microfibrils -> tensile strength.', 6, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Describe the four levels of protein structure.', 'Primary: amino acid sequence (peptide bonds). Secondary: alpha helix / beta pleated sheet (H-bonds between C=O and N-H). Tertiary: 3D fold (H-bonds, ionic, disulfide, hydrophobic). Quaternary: 2+ subunits (e.g. haemoglobin: 4 chains + haem).', 7, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Describe the structure of a DNA nucleotide and the formation of a polynucleotide.', 'Nucleotide = phosphate + deoxyribose + base (A/T/C/G). Nucleotides join 5'' to 3'' by phosphodiester bonds (condensation). Two antiparallel strands wind into a double helix held by H-bonds (A=T, G≡C).', 8, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Explain induced-fit enzyme catalysis.', 'Substrate binds the active site; enzyme subtly changes shape so the active site moulds tightly around the substrate. This places strain on bonds in the substrate, lowering Ea. Enzyme returns to original shape after products leave.', 9, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Compare competitive and non-competitive inhibitors.', 'Competitive: similar shape to substrate, binds active site; effect overcome by raising [substrate]. Non-competitive: binds an allosteric site, distorts the active site so substrate cannot bind; effect not overcome by raising [substrate].', 10, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Describe the fluid-mosaic model.', 'A phospholipid bilayer with proteins (channels, carriers, receptors) embedded in the fluid. Glycoproteins/glycolipids for cell signalling and recognition. Cholesterol regulates fluidity. Hydrophilic heads outwards, hydrophobic tails inwards.', 11, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Compare diffusion, facilitated diffusion, osmosis and active transport.', 'Diffusion: passive, no protein. Facilitated diffusion: passive, via channel/carrier proteins. Osmosis: passive, water down a water-potential gradient. Active transport: ATP-driven, against gradient via carrier proteins.', 12, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Define water potential and predict cell behaviour.', 'Water potential = pressure exerted by water molecules; pure water = 0 kPa, solutions are negative. Animal cells: lyse in hypotonic solution, crenate in hypertonic. Plant cells: turgid in hypotonic (cell wall resists), plasmolysed in hypertonic.', 13, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Explain co-transport of glucose into ileum epithelial cells.', 'Na+/K+ pump on basal membrane uses ATP to pump Na+ out, lowering Na+ in cell. Na+ then re-enters with glucose via a co-transporter on the apical surface (down its gradient). Glucose then leaves into the blood by facilitated diffusion.', 14, 'alevel'),
  ('Biology', 'OCR B', 'B2', 'Cells, Chemicals and Transport', 'Describe gas exchange in mammalian alveoli.', 'Many alveoli (large total SA ~70 m^2), squamous epithelium one cell thick (short diffusion path), surrounded by capillaries (gradient maintained by ventilation and circulation), thin film of fluid for dissolved gases, surfactant lowers surface tension.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Describe the eukaryotic cell cycle.', 'G1: cell growth, organelle replication. S: DNA replication. G2: further growth, error check. M: mitosis (PMAT). Cytokinesis. Checkpoints (G1/S, G2/M, spindle) prevent damaged cells progressing.', 1, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Outline the four stages of mitosis.', 'Prophase: chromosomes condense, nuclear envelope breaks down, centrioles move to poles. Metaphase: chromosomes align on equator. Anaphase: spindle pulls sister chromatids to poles. Telophase: nuclear envelopes reform.', 2, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Compare mitosis and meiosis.', 'Mitosis: 1 division, 2 diploid identical daughter cells, growth/repair. Meiosis: 2 divisions, 4 haploid genetically distinct gametes, with independent assortment and crossing over. Source of genetic variation -> evolution.', 3, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Describe two sources of genetic variation in meiosis.', 'Independent assortment of homologous chromosomes (metaphase I) and sister chromatids (metaphase II). Crossing over: in prophase I, non-sister chromatids exchange DNA at chiasmata, producing new allele combinations.', 4, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Define totipotent, pluripotent, multipotent, unipotent.', 'Totipotent: any cell type incl. extra-embryonic. Pluripotent: any embryonic cell type. Multipotent: limited types (e.g. haematopoietic). Unipotent: one type (e.g. cardiac muscle progenitor).', 5, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Outline how stem cells differentiate.', 'Differentiation results from selective gene expression. Specific transcription factors activate cell-type-specific genes; epigenetic changes (DNA methylation, histone modification) silence others. Position-dependent signals (morphogens) and microenvironment guide specialisation.', 6, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Outline the benefits and ethical issues of using human embryonic stem cells.', 'Benefits: pluripotent -> potential regenerative therapies (Parkinson''s, spinal injury). Ethics: destruction of embryos; iPS cells offer an alternative with fewer concerns. Strict regulation by HFEA in the UK.', 7, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Describe how oncogenes and tumour suppressor genes lead to cancer.', 'Proto-oncogenes regulate cell division; mutation makes them constitutively active oncogenes -> uncontrolled division. Tumour suppressor genes (e.g. p53) normally pause the cycle; loss-of-function mutations remove this brake. Both contribute to malignant tumours.', 8, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Compare benign and malignant tumours.', 'Benign: slow-growing, encapsulated, do not metastasise (e.g. lipoma). Malignant: rapid, invade tissues, metastasise via blood or lymph. Multiple gene mutations needed; many cancers also show altered DNA methylation patterns (epigenetic).', 9, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Compare innate (non-specific) and specific immune responses.', 'Innate: skin, mucus, lysozyme, phagocytosis, inflammation, fever. Fast but non-specific. Specific: B cells (antibodies), T helpers, T killers, memory cells. Slower at first exposure but produces immunological memory.', 10, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Describe phagocytosis.', 'Phagocyte chemotaxes towards pathogen, recognises by receptors, engulfs by endocytosis -> phagosome. Lysosomes fuse with phagosome -> phagolysosome; lysozyme digests pathogen. Antigens displayed on MHC II for T-cell activation.', 11, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Outline vaccination and herd immunity.', 'Vaccines contain weakened/inactivated pathogens or antigens, triggering primary response and memory cells. If high enough proportion vaccinated, pathogen cannot spread, protecting unvaccinated (herd immunity). Threshold depends on R0.', 12, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Compare bacterial, viral, fungal and protoctist diseases with examples.', 'Bacterial: TB (M. tuberculosis). Viral: HIV. Fungal: athlete''s foot (Tinea); plant — black sigatoka. Protoctist: malaria (Plasmodium); potato late blight.', 13, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'How do antibiotics work and how does resistance arise?', 'Bactericidal (penicillin: weakens peptidoglycan -> lysis) or bacteriostatic (tetracyclines: block 70S ribosomes). Resistance: random mutations -> resistant variants survive and reproduce; resistance genes spread by plasmid conjugation. Misuse accelerates this.', 14, 'alevel'),
  ('Biology', 'OCR B', 'B3', 'Cell Division, Development and Disease', 'Describe how malaria is transmitted and prevented.', 'Plasmodium parasites transmitted by female Anopheles mosquito biting. Inside the host, multiplies in liver then RBCs, causing fever cycles. Prevention: insecticide-treated nets, indoor spraying, antimalarials, drainage of standing water, vaccines (RTS,S).', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Write the photosynthesis equation and identify oxidation/reduction.', '6CO2 + 6H2O -> C6H12O6 + 6O2 (sunlight, chlorophyll). CO2 is reduced (gains H/electrons) to glucose; H2O is oxidised to O2 in photolysis at PSII.', 1, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Outline the light-dependent reactions.', 'Photolysis at PSII: 2H2O -> 4H+ + 4e- + O2. Excited e- pass down ETC, pumping H+ into thylakoid lumen. Chemiosmosis: H+ flow back through ATP synthase -> ATP. NADP+ + H+ + 2e- -> NADPH. Cyclic photophosphorylation produces only ATP.', 2, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Describe the Calvin cycle.', 'CO2 + RuBP (5C) -> 2 GP (3C) (catalysed by RuBisCO). GP reduced to TP using ATP and NADPH. Some TP forms hexose; most regenerates RuBP using ATP. Six turns yield one glucose.', 3, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'How do CO2, light and temperature affect photosynthesis?', 'Each can be a limiting factor when in shortest supply. Low light: rate limited by photolysis. Low CO2: rate limited by Calvin cycle. Below optimum T: enzymes slow; above ~30 °C: RuBisCO denatures, stomata close.', 4, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'List the four stages of aerobic respiration with location.', 'Glycolysis (cytoplasm), link reaction (matrix), Krebs cycle (matrix), oxidative phosphorylation / ETC (inner mitochondrial membrane / cristae).', 5, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Outline glycolysis.', 'Glucose phosphorylated using 2 ATP -> hexose bisphosphate -> 2 triose phosphate. Each TP oxidised to pyruvate; net 2 ATP and 2 NADH per glucose. Anaerobic; in cytoplasm.', 6, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Describe the link reaction and Krebs cycle.', 'Link: 2 pyruvate -> 2 acetyl-CoA + 2 CO2 + 2 NADH. Krebs (x2): each acetyl-CoA + 4C -> 6C; decarboxylation/dehydrogenation give 2 CO2, 3 NADH, 1 FADH2 and 1 ATP per turn (per glucose: 4 CO2, 6 NADH, 2 FADH2, 2 ATP).', 7, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Explain oxidative phosphorylation by chemiosmosis.', 'NADH/FADH2 deliver e- to ETC on inner membrane. As electrons pass between carriers, H+ is pumped to the intermembrane space. H+ flows back through ATP synthase -> ATP. O2 is final acceptor: O2 + 4H+ + 4e- -> 2H2O. Theoretical yield ~32 ATP per glucose.', 8, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Compare lactate and ethanol fermentation.', 'Animals: pyruvate + NADH -> lactate + NAD+; reversible (lactate cleared in liver -> oxygen debt). Yeast/plants: pyruvate -> ethanal + CO2 -> ethanol + NAD+; irreversible. Both regenerate NAD+ for glycolysis to continue without O2.', 9, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Define an ecosystem and describe energy flow.', 'Ecosystem = community + abiotic environment. Energy enters as light, captured by producers (NPP), passes to herbivores and carnivores. Loss at each level: respiration, heat, faeces, excretion. ~10% transfer typical -> short food chains.', 10, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Define GPP, NPP and their relationship.', 'GPP = total chemical energy fixed by producers per area per time. NPP = GPP - R (respiratory loss). Units: kJ m^-2 yr^-1. NPP is energy available to next trophic level.', 11, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Outline the carbon and nitrogen cycles.', 'Carbon: photosynthesis fixes CO2; respiration, combustion and decomposition return it. Nitrogen: saprobionts -> NH4+; nitrifiers -> NO2- -> NO3-; nitrogen-fixing bacteria N2 -> NH3; denitrifiers reduce NO3- -> N2 in anaerobic soils.', 12, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Compare carrying capacity and density-dependent / -independent factors.', 'Carrying capacity: maximum population an environment can sustain. Density-dependent: food, predation, disease (act more strongly as density rises). Density-independent: drought, fire, flooding (act regardless of density).', 13, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Describe primary succession from bare rock to climax community.', 'Pioneer species (lichens) colonise bare rock, weather it and add organic matter. Mosses follow, then small plants, grasses, shrubs and finally woodland (climax). Each stage modifies the abiotic conditions for the next.', 14, 'alevel'),
  ('Biology', 'OCR B', 'B4', 'Energy, Reproduction and Populations', 'Outline Darwin''s theory of natural selection.', '1) Variation within a population. 2) More offspring produced than survive. 3) Individuals with advantageous alleles more likely to survive and reproduce. 4) These alleles increase in frequency over generations -> evolution.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe semi-conservative DNA replication.', 'Helicase unwinds the helix; H-bonds break. Free DNA nucleotides align with their complement on each parental template. DNA polymerase joins them by phosphodiester bonds (5''-3''). Each daughter molecule has one parental and one new strand.', 1, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Outline transcription and post-transcriptional modification.', 'Gene unwinds; RNA polymerase joins free RNA nucleotides to a template strand (U replaces T) -> pre-mRNA. Splicing removes introns; exons rejoin. 5'' cap and poly-A tail added. Mature mRNA exits via nuclear pore.', 2, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe translation step by step.', 'mRNA binds the small ribosomal subunit; tRNA carrying methionine binds AUG. Next tRNA (anticodon complementary to next codon) binds; peptide bond forms. Ribosome translocates one codon. Continues until a stop codon -> polypeptide released.', 3, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe how transcription factors regulate gene expression.', 'Transcription factors bind specific promoter sequences and either recruit (activators) or block (repressors) RNA polymerase. They are produced in response to internal/external signals, ensuring only relevant genes are transcribed in a given cell type.', 4, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Distinguish DNA methylation and histone modification (epigenetics).', 'DNA methylation: -CH3 added to cytosine, typically silences transcription. Histone acetylation: loosens DNA-histone binding -> easier transcription. Histone methylation can either activate or silence depending on residue. Reversible and inheritable.', 5, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe a monohybrid and a dihybrid cross.', 'Mono: Aa x Aa -> 3:1 dominant:recessive. Di: AaBb x AaBb -> 9:3:3:1 (assuming no linkage). Use Punnett squares to predict ratios; chi-squared tests if observed differs significantly from expected.', 6, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Explain codominance and the ABO blood system.', 'I^A and I^B alleles are codominant (both expressed in heterozygotes -> AB blood). I^O is recessive. Genotypes: I^A I^A or I^A I^O = A; I^B I^B or I^B I^O = B; I^A I^B = AB; I^O I^O = O.', 7, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe sex linkage with haemophilia.', 'Allele on X chromosome (X^h, recessive). Females need two X^h to be affected; one X^h makes a carrier. Males with X^h Y are hemizygous and affected. Hence haemophilia much more common in males.', 8, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'State the Hardy-Weinberg equations and assumptions.', 'p + q = 1; p^2 + 2pq + q^2 = 1. Assumes large population, random mating, no migration / mutation / selection. Useful for estimating carrier frequencies (e.g. cystic fibrosis).', 9, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Explain the resting potential and an action potential.', 'Resting: Na+/K+ pump (3 Na+ out / 2 K+ in) plus K+ leak channels -> -70 mV. AP: stimulus -> Na+ channels open (depolarisation to +40 mV) -> Na+ close, K+ open (repolarisation) -> hyperpolarisation -> Na+/K+ pump restores resting.', 10, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe synaptic transmission at a cholinergic synapse.', 'AP arrives -> Ca2+ channels open -> Ca2+ enters -> vesicles fuse with membrane and release ACh. ACh binds postsynaptic receptors, opens Na+ channels. Acetylcholinesterase hydrolyses ACh; choline recycled.', 11, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe how insulin and glucagon regulate blood glucose.', 'Beta cells release insulin: more GLUT4 transporters -> glucose uptake; activates glycogen synthase -> glycogenesis. Alpha cells release glucagon: cAMP second messenger -> phosphorylates glycogen phosphorylase -> glycogenolysis -> glucose released to blood.', 12, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe ultrafiltration and selective reabsorption in the nephron.', 'Glomerulus: high BP forces small molecules through fenestrated capillaries, basement membrane, and podocyte slits into Bowman''s capsule. PCT: Na+ pumped out into blood; Na+ re-enters with glucose / amino acids by co-transport; water follows osmotically.', 13, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Outline ADH control of water balance.', 'High blood solute concentration -> osmoreceptors in hypothalamus stimulate posterior pituitary to release ADH -> binds collecting duct receptors -> aquaporins inserted -> more water reabsorbed -> small volume of concentrated urine.', 14, 'alevel'),
  ('Biology', 'OCR B', 'B5', 'Genetics, Control and Homeostasis', 'Describe thermoregulation in mammals.', 'Hypothalamus monitors blood T. Too cold: vasoconstriction, shivering, hair erected, thyroxine release. Too hot: vasodilation, sweating, hair flattens. Behavioural responses (seek shade, change posture) supplement physiological control.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Describe how restriction enzymes and ligase build recombinant DNA.', 'Restriction endonucleases cut DNA at palindromic sequences leaving sticky ends. The same enzyme used on the gene and the vector creates complementary ends. DNA ligase forms phosphodiester bonds between them, producing recombinant DNA.', 1, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Outline gene cloning using a bacterial plasmid.', 'Cut gene and plasmid with the same restriction enzyme -> complementary sticky ends. DNA ligase joins gene into plasmid -> recombinant DNA. Plasmid taken up by host bacterium (CaCl2 + heat shock). Marker genes identify successful uptake.', 2, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Outline polymerase chain reaction (PCR).', 'Cycles: 95 °C denature, ~55 °C anneal primers, 72 °C extend with Taq polymerase. Each cycle doubles DNA -> 2^n copies after n cycles. Used in cloning, sequencing and DNA profiling.', 3, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Outline DNA profiling using STRs.', 'Extract DNA, amplify short tandem repeat (STR) regions by PCR, separate fragments by gel/capillary electrophoresis. Each individual has a near-unique STR profile -> banding pattern. Used in identification, paternity, forensics.', 4, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Describe gel electrophoresis principles.', 'DNA fragments are loaded into wells in agarose; an electric field pulls negatively charged DNA towards the anode. Smaller fragments move further. Bands are visualised with UV after staining (e.g. ethidium bromide). Compared to a marker / reference ladder.', 5, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Outline how to make recombinant insulin.', 'Reverse transcriptase converts insulin mRNA from human pancreas to cDNA. Sticky ends added (RE) and ligated into a plasmid vector. E. coli host transformed; selected with antibiotic-resistance markers. Bacteria cultured; insulin extracted and purified.', 6, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Compare somatic and germline gene therapy.', 'Somatic: alters body cells of an individual (e.g. CFTR delivered to lung cells in CF) — not heritable. Germline: alters egg/sperm/embryo so changes are passed on; banned in humans for ethical reasons.', 7, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Outline CRISPR-Cas9 gene editing.', 'A guide RNA matches the target DNA sequence; Cas9 nuclease cuts both strands. The cell repairs the break, either by error-prone NHEJ (knock-out) or by homology-directed repair using a donor template (precise edit).', 8, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Compare natural and artificial cloning of plants and animals.', 'Plants: vegetative propagation (runners), tissue culture (totipotent cells -> callus -> plantlets). Animals: identical twins (natural); artificial: nuclear transfer (Dolly, somatic cell nuclear transfer); embryo splitting in livestock.', 9, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Compare batch and continuous fermentation.', 'Batch: nutrients added once, products accumulate; reactor cleaned between runs. Useful for secondary metabolites (penicillin). Continuous: nutrients added and product removed throughout; ideal for primary metabolites (e.g. enzymes); more efficient.', 10, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Describe immobilised enzymes and one advantage.', 'Enzymes bound to or trapped within a solid support (alginate beads, gel, membrane). Reusable, easier product separation, more stable to T/pH. Used in industrial processes (glucose isomerase, lactose-free milk).', 11, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Describe the carbon cycle and human impact.', 'Photosynthesis fixes CO2; respiration, combustion and decomposition return it. Carbon stored in biomass, soil, oceans, fossil fuels. Human burning of fossil fuels and deforestation increases atmospheric CO2 -> enhanced greenhouse effect -> global warming.', 12, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'List evidence for climate change.', 'Direct: ice core CO2 / temperature, atmospheric CO2 (Mauna Loa), satellite data, sea-level rise, glacier retreat. Indirect: dendrochronology, pollen analysis, isotope ratios. Multiple independent lines converge on warming.', 13, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Describe how rising temperatures affect species distribution.', 'Species shift poleward and upward in altitude as temperatures rise; phenological mismatches occur (flowering vs pollinators); range contractions if no migration possible (e.g. mountain-top species). Loss of habitat and mismatched timing reduce reproductive success.', 14, 'alevel'),
  ('Biology', 'OCR B', 'B6', 'Biotechnology, Ecosystems and Human Impact', 'Compare in situ and ex situ conservation.', 'In situ: protect species in natural habitat (national parks). Preserves ecological interactions but vulnerable to disasters. Ex situ: zoos, seed banks, botanical gardens. Controlled but smaller gene pool, risk of inbreeding.', 15, 'alevel');
INSERT INTO flashcards (subject, exam_board, topic_id, topic_name, front, back, card_order, level) VALUES
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 1: microscopy and measuring cells.', 'Calibrate eyepiece graticule against a stage micrometer at each magnification. Mount specimen, focus low power first. Measure cells in graticule divisions, then convert using calibration. Calculate magnification (image / actual).', 1, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 2: dissection of an organ (e.g. heart).', 'Pin out external features, identify chambers and vessels. Cut along septum; observe atria (thinner walls), ventricles (thicker, especially LV), AV and SL valves, papillary muscles and chordae tendineae. Sharps disposal; gloves.', 2, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 3: sampling organisms in a habitat.', 'Random sampling: random coordinates with quadrats. Systematic: line/belt transect across an environmental gradient. Calculate species frequency, percentage cover and density. Mark-release-recapture for mobile organisms: N = (n1 x n2) / m.', 3, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 4: chromatography of plant pigments.', 'Grind leaves with sand and propanone. Spot solvent front on chromatography paper, spot pigments, place in solvent. Calculate Rf = distance moved by spot / distance moved by solvent. Compare Rf to known pigments (chlorophyll a, b, carotene, xanthophyll).', 4, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 5: investigating enzyme activity.', 'Use catalase + H2O2 (gas syringe collects O2) or amylase + starch (iodine end-point on tile). Vary T, pH or [substrate]. Plot rate vs IV. Control: [enzyme], buffers, mixing time. Determine optimum and explain via active-site shape.', 5, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 6: investigating osmosis.', 'Cut equal-mass potato cylinders. Place in solutions of varied [sucrose]. After fixed time, blot and reweigh. Plot % change in mass vs [sucrose]. Where mass change = 0, water potential of potato = solution. Control T, time, surface area.', 6, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 7: investigating photosynthesis.', 'Submerge pondweed (Cabomba/Elodea) in NaHCO3 solution (CO2 source). Vary light intensity (lamp distance) or wavelength (filters). Count bubbles per minute or use a gas syringe. Plot rate vs intensity. Control T, [CO2], pH.', 7, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 8: investigating respiration.', 'Place germinating peas with KOH (CO2 absorber) in sealed tube; manometer fluid moves as O2 consumed. Use thermostatically controlled bath. Control: glass beads (no respiration). Calculate volume of O2 used per unit time per gram of organism. <svg viewBox="0 0 220 90" width="200" height="80" style="display:block;margin:6px auto"><rect x="20" y="25" width="60" height="40" fill="none" stroke="#0B1E3F" stroke-width="1.5"/><text x="36" y="48" font-size="9" fill="#0B1E3F">seeds</text><text x="32" y="60" font-size="8" fill="#0B1E3F">+ KOH</text><line x1="80" y1="45" x2="200" y2="45" stroke="#0B1E3F" stroke-width="1.5"/><circle cx="120" cy="45" r="3" fill="#A33"/><text x="100" y="35" font-size="9" fill="#0B1E3F">manometer</text><text x="115" y="60" font-size="9" fill="#A33">droplet</text></svg>', 8, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 9: aseptic microbiology techniques.', 'Sterilise loop in flame, work near a Bunsen, lift agar lid only briefly. Spread bacterial culture, place soaked discs of antimicrobials. Incubate <25 °C. Measure zones of inhibition (diameter or area). Larger zone = greater antimicrobial activity.', 9, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Outline Practical 10: gel electrophoresis.', 'Prepare agarose gel; load DNA samples + loading dye into wells. Apply voltage; DNA migrates towards anode (negatively charged). Smaller fragments move further. Stain (e.g. ethidium bromide) and visualise under UV. Compare to ladder for sizing.', 10, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 11: heart rate and ventilation during exercise.', 'Record resting heart rate and breathing rate. Subject exercises (steady cycle / step) for 3-5 min; record during recovery. Plot rate vs time. Use a pulse oximeter / spirometer. Control fitness level, pre-test rest period.', 11, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'Describe Practical 12: plant tropisms.', 'Grow seedlings (e.g. cress) in different light conditions: unilateral light, dark, all-around light. Measure curvature of stems and roots. Positive phototropism in shoots; negative phototropism in roots. Control: T, water, type of seed.', 12, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'How is a serial dilution prepared accurately?', 'Pipette equal volumes (e.g. 1 cm^3) of stock into test tubes. Add equal volumes of solvent (e.g. 9 cm^3 distilled water) to each. Mix between transfers. This creates a 10-fold dilution series. Use a fresh pipette tip each time to prevent cross-contamination.', 13, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'How is a colorimeter used in biology?', 'Choose a filter complementary to the solution colour (e.g. red for blue solution). Zero with a blank. Make standards of known concentration; plot calibration curve of absorbance vs [conc]. Read unknown concentration off curve from its absorbance.', 14, 'alevel'),
  ('Biology', 'OCR B', 'PA', 'Practical Activities', 'How is data analysed and a conclusion drawn?', 'Plot graph (line / scatter / bar / histogram); identify pattern. Calculate gradient / rate / mean / SD. Apply statistical test (t-test, chi^2, Spearman) at p = 0.05. Conclusion: link to hypothesis; consider limitations and improvements.', 15, 'alevel');
